def print_per_thread_timeline(timelines):
    print_header("多线程时间线分析 (按线程独立标注)")
    for tkey, tinfo in timelines.items():
        label = tkey.replace("_", " ").title()
        tid = tinfo["tid"]
        tname = tinfo.get("name", "")
        role = tinfo.get("role", tkey)
        print(f"  ── {label}: {tname} [pid={tid[0]}, tid={tid[1]}] ──")
        print(f"    事件总数: {tinfo['total_events']}")
        print(f"    {'事件名称':<65} {'类别':>12} {'耗时':>12}")
        print(f"    {'─'*65} {'─'*12} {'─'*12}")
        for ev in tinfo["top_events"]:
            print(f"    {ev['name'][:65]:<65} {ev['cat']:>12} {format_duration(ev['dur']):>12}")
        print()


def save_per_thread_timeline_md(timelines, L):
    L.append("## 多线程时间线分析\n")
    L.append("> 各线程独立分析，以主线程和 GPU ProfilerStep 为主。\n")
    for tkey, tinfo in timelines.items():
        label = tkey.replace("_", " ").title()
        tid = tinfo["tid"]
        tname = tinfo.get("name", "")
        L.append(f"### {label}: {tname} [pid={tid[0]}, tid={tid[1]}]\n")
        L.append(f"事件总数: {tinfo['total_events']}\n")
        L.append("| 事件名称 | 类别 | 耗时 |")
        L.append("|----------|------|------|")
        for ev in tinfo["top_events"]:
            L.append(f"| {ev['name'][:80]} | {ev['cat']} | {format_duration(ev['dur'])} |")
        L.append("")


# ===========================================================================
# Kernel call stack report
# ===========================================================================

def print_kernel_call_stacks(kernel_stacks, gpu_info):
    if not kernel_stacks:
        return
    print_header("Kernel 热点调用栈分析")
    for kname, info in list(kernel_stacks.items())[:10]:
        dur = info["total_dur"]
        pct = dur / gpu_info["gpu_step_dur"] * 100 if gpu_info.get("gpu_step_dur", 0) > 0 else 0
        print(f"  ── {kname[:80]} ({format_duration(dur)}, {pct:.2f}%, count={info['count']}) ──")
        stack = info["stack"]
        for line in stack.strip().split("\n")[:12]:
            print(f"    {line.strip()}")
        print()


def save_kernel_call_stacks_md(kernel_stacks, gpu_info, L):
    if not kernel_stacks:
        return
    L.append("## Kernel 热点调用栈\n")
    for kname, info in list(kernel_stacks.items())[:10]:
        dur = info["total_dur"]
        pct = dur / gpu_info["gpu_step_dur"] * 100 if gpu_info.get("gpu_step_dur", 0) > 0 else 0
        L.append(f"### {kname[:80]}\n")
        L.append(f"- 耗时: {format_duration(dur)} ({pct:.2f}%), 次数: {info['count']}\n")
        L.append("```")
        stack = info["stack"]
        for line in stack.strip().split("\n")[:15]:
            L.append(line.strip())
        L.append("```\n")


# ===========================================================================
# lagrange_torch reference report
# ===========================================================================

def print_lagrange_refs(lagrange_refs):
    if not lagrange_refs:
        return
    print_header("lagrange_torch 框架引用")
    print(f"  仓库地址: {LAGRANGE_TORCH_REPO}\n")
    for ref in lagrange_refs:
        print(f"  Kernel: {ref['kernel_name'][:80]}")
        print(f"    耗时: {format_duration(ref['dur'])}, 次数: {ref['count']}")
        if ref["op_name"]:
            print(f"    算子: {ref['op_name']}")
            if ref["search_url"]:
                print(f"    源码搜索: {ref['search_url']}")
        print()


def save_lagrange_refs_md(lagrange_refs, L):
    if not lagrange_refs:
        return
    L.append("## lagrange_torch 框架引用\n")
    L.append(f"仓库地址: [{LAGRANGE_TORCH_REPO}]({LAGRANGE_TORCH_REPO})\n")
    L.append("| Kernel | 耗时 | 次数 | 算子 | 源码链接 |")
    L.append("|--------|------|------|------|----------|")
    for ref in lagrange_refs:
        op = ref["op_name"] or "-"
        link = f"[搜索]({ref['search_url']})" if ref["search_url"] else "-"
        L.append(f"| {ref['kernel_name'][:70]} | {format_duration(ref['dur'])} | {ref['count']} | {op} | {link} |")
    L.append("")


# ===========================================================================
# Markdown report
# ===========================================================================

def save_markdown_report(meta, trace_type, step_dur_us, step_decomp, thread_info, workers,
                         mod_info, gpu_info, dh_info, output_path, max_level=None,
                         src_info=None, source_files=None, timelines=None,
                         kernel_stacks=None, lagrange_refs=None, screenshot_path=None,
                         num_steps=1, overlap_info=None):
    L = []
    L.append("# Torch Trace 训练分析报告\n")

    # Overview
    L.append("## 概览\n")
    L.append(f"- **Trace 类型**: {'训练' if trace_type == 'training' else '推理'}")
    L.append(f"- **设备**: {meta.get('device_name', 'N/A')}")
    if meta.get("world_size", 1) > 1:
        L.append(f"- **分布式**: rank {meta.get('rank', 0)} / world_size {meta.get('world_size', 1)}")
    L.append(f"- **ProfilerStep 数**: {num_steps}")
    L.append(f"- **平均 Step 耗时**: {format_duration(step_dur_us)} (所有数据已按 {num_steps} 步平均)")
    L.append("")

    if step_decomp:
        L.append("### Step 分解\n")
        L.append("| 阶段 | 耗时 | 占比 |")
        L.append("|------|------|------|")
        sdur = step_decomp.get("step_dur", step_dur_us)
        if "forward_backward_dur" in step_decomp:
            L.append(f"| forward_backward | {format_duration(step_decomp['forward_backward_dur'])} | {pct_str(step_decomp['forward_backward_dur'], sdur)} |")
        if "optimize_dur" in step_decomp:
            L.append(f"| optimize | {format_duration(step_decomp['optimize_dur'])} | {pct_str(step_decomp['optimize_dur'], sdur)} |")
        if "other_dur" in step_decomp:
            L.append(f"| other | {format_duration(step_decomp['other_dur'])} | {pct_str(step_decomp['other_dur'], sdur)} |")
        L.append("")

    # Thread overview
    L.append("## 线程分析\n")
    L.append("| 线程 | 角色 | 事件数 | 总耗时 | Modules |")
    L.append("|------|------|--------|--------|---------|")
    for w in workers:
        mod_str = ", ".join(w["modules"][:3]) if w["modules"] else "-"
        L.append(f"| {w['name']} | {w['role']} | {w['event_count']} | {format_duration(w['total_dur'])} | {mod_str} |")
    L.append("")

    # Module tree
    L.append("## Module 耗时分析\n")
    L.append("### Module 层级树\n")
    L.append("```")
    old_stdout = sys.stdout
    sys.stdout = buf = io.StringIO()
    print_module_tree(mod_info, "ROOT", 0, step_dur_us, mod_info.get("module_thread_info"))
    tree_str = buf.getvalue()
    sys.stdout = old_stdout
    L.append(tree_str)
    L.append("```\n")

    depth_map = mod_info["depth_map"]
    max_depth = mod_info["max_depth"]
    if max_level is not None:
        max_depth = min(max_depth, max_level)

    for level in range(max_depth + 1):
        level_modules = [n for n, d in depth_map.items() if d == level]
        if not level_modules:
            continue
        level_modules.sort(key=lambda n: mod_info["module_durations"].get(n, 0), reverse=True)
        L.append(f"### Level {level} Modules\n")
        L.append("| Module | Thread | Inclusive | Exclusive | Incl% | Excl% | Calls |")
        L.append("|--------|--------|----------|-----------|-------|-------|-------|")
        for name in level_modules:
            inc = mod_info["module_durations"].get(name, 0)
            exc = mod_info["module_exclusive"].get(name, 0)
            calls = mod_info["module_call_counts"].get(name, 0)
            short = name.replace("nn.Module: ", "")
            ti = mod_info["module_thread_info"].get(name, {})
            roles = ti.get("roles", set())
            tag = "worker" if ("worker_thread" in roles and "main_thread" not in roles) else "main" if "main_thread" in roles else "other"
            L.append(f"| {short} | {tag} | {format_duration(inc)} | {format_duration(exc)} | {pct_str(inc, step_dur_us)} | {pct_str(exc, step_dur_us)} | {calls} |")
        L.append("")

    # GPU timeline
    if gpu_info:
        L.append("## GPU 时间线分析\n")
        L.append(f"- **GPU 利用率**: {gpu_info['gpu_utilization']:.1f}%")
        L.append(f"- **Kernel 活跃时间**: {format_duration(gpu_info['total_kernel_dur'])}")
        L.append(f"- **Kernel 间隙时间**: {format_duration(gpu_info['total_gap'])}")
        L.append("")

        L.append("### Top 热点 Kernel\n")
        L.append("| Kernel | 耗时 | 占比 | 次数 | Host Module |")
        L.append("|--------|------|------|------|-------------|")
        for kname, info in gpu_info["top_kernels"]:
            pct = pct_str(info["dur"], gpu_info["gpu_step_dur"])
            modules = gpu_info["top_kernel_modules"].get(kname, [])
            mod_str = modules[0][0] if modules else "N/A"
            L.append(f"| {kname[:80]} | {format_duration(info['dur'])} | {pct} | {info['count']} | {mod_str} |")
        L.append("")

        L.append("### Top Kernel 间隙\n")
        L.append("| 间隙时长 | 前一个 Kernel | 后一个 Kernel |")
        L.append("|----------|---------------|---------------|")
        for g in gpu_info["top_gaps"][:15]:
            L.append(f"| {format_duration(g['gap_us'])} | {g['before_name'][:50]} | {g['after_name'][:50]} |")
        L.append("")

    # Device/Host
    L.append("## Device/Host 耗时总览\n")
    host = dh_info["host_total_us"]
    device = dh_info["device_total_us"]
    L.append("| 类别 | 耗时 | 占比 |")
    L.append("|------|------|------|")
    L.append(f"| Host (CPU) | {format_duration(host)} | {pct_str(host, step_dur_us)} |")
    L.append(f"| Device (GPU) | {format_duration(device)} | {pct_str(device, step_dur_us)} |")
    L.append("")

    L.append("### Device 耗时分解\n")
    L.append("| 类别 | 耗时 | 占比 |")
    L.append("|------|------|------|")
    for cat, dur in sorted(dh_info["device_breakdown"].items(), key=lambda x: -x[1]):
        L.append(f"| {cat} | {format_duration(dur)} | {pct_str(dur, step_dur_us)} |")
    L.append("")

    # Comm/compute overlap
    if overlap_info:
        save_comm_compute_overlap_md(overlap_info, gpu_info, L)

    # Source hotspot
    if src_info and source_files:
        save_source_hotspot_markdown(src_info, source_files, L)

    # Per-thread timeline
    if timelines:
        save_per_thread_timeline_md(timelines, L)

    # Kernel call stacks
    if kernel_stacks and gpu_info:
        save_kernel_call_stacks_md(kernel_stacks, gpu_info, L)

    # lagrange_torch references
    if lagrange_refs:
        save_lagrange_refs_md(lagrange_refs, L)

    # Screenshot
    if screenshot_path:
        rel_path = os.path.basename(screenshot_path)
        L.append("## Trace 可视化\n")
        L.append(f"![Trace Screenshot]({rel_path})\n")

    with open(output_path, "w") as f:
        f.write("\n".join(L))
    print(f"  Markdown 报告已保存到: {output_path}")


# ===========================================================================
# HTML Flowchart Generation (Source-Code First)
# ===========================================================================

def build_static_module_tree(source_files, preferred_root=None):
    """Build module hierarchy tree purely from source code.
    Args:
        source_files: dict of {filename: [lines]}
        preferred_root: optional class name to use as primary root if present in tree.
            Useful when timeline indicates a specific top-level wrapper (e.g. DDPAwemeLiveCVR
            implies AwemeLiveCVR is the actual model entry-point).
    Returns: tree dict, root list, class_map
    """
    class_map = _build_class_map(source_files)
    module_call_order, _ = _build_source_dependency_order(source_files, class_map)

    # ------------------------------------------------------------------
    # 轻量常量表：用于 ModuleList/ModuleDict 展开时解析 range(N) / layers=CONST
    # 仅解析“文件级”形如 `NAME = 6` 的 int 常量。
    # ------------------------------------------------------------------
    file_int_consts = {}
    _INT_CONST_RE = re.compile(r'^\s*([A-Z][A-Z0-9_]*)\s*=\s*(\d+)\s*(?:#.*)?$')
    for _fname, _lines in source_files.items():
        consts = {}
        for _line in _lines:
            m = _INT_CONST_RE.match(_line)
            if m:
                consts[m.group(1)] = int(m.group(2))
        file_int_consts[_fname] = consts

    # 全局常量：同名常量在多个文件出现时，若值唯一则可跨文件解析
    global_int_const_values = defaultdict(set)
    for _fname, _cs in file_int_consts.items():
        for _k, _v in _cs.items():
            global_int_const_values[_k].add(_v)

    # ctor_kw_int_args[ClassName][kw] = {1,2,...}
    ctor_kw_int_args = defaultdict(lambda: defaultdict(set))

    def _eval_int_atom(expr: str, fname: str):
        expr = (expr or '').strip()
        if not expr:
            return None
        if re.fullmatch(r'\d+', expr):
            return int(expr)
        consts = file_int_consts.get(fname, {})
        if expr in consts:
            return consts[expr]
        # 跨文件唯一常量
        vals = global_int_const_values.get(expr)
        if vals and len(vals) == 1:
            return next(iter(vals))
        return None

    def _extract_kw_int_args(call_text: str, fname: str):
        """从 `Foo(a=..., b=...)` 的参数串中尽量提取 kw=int/CONST。
        不做真正的括号/字符串完整解析，只做足够安全的近似：只匹配最外层的 `kw = ATOM`。
        """
        out = {}
        if not call_text:
            return out
        # 先粗暴移除字符串内容，避免在字符串里误命中 kw=
        scrub = re.sub(r"([\"\']).*?\1", "''", call_text)
        for m in re.finditer(r'\b(\w+)\s*=\s*([A-Z][A-Z0-9_]*|\d+)\b', scrub):
            k = m.group(1)
            v = _eval_int_atom(m.group(2), fname)
            if v is not None:
                out[k] = v
        return out

    # Build inheritance info - detect which classes extend nn.Module (or other user classes)
    nn_module_classes = set()
    for fname, lines in source_files.items():
        for line in lines:
            m = re.match(r'^class (\w+)\(([^)]+)\)', line.strip())
            if m:
                cname, bases = m.groups()
                base_list = [b.strip() for b in bases.split(",")]
                for b in base_list:
                    b_short = b.split(".")[-1]
                    if b_short in ("Module", "nn.Module") or b_short in nn_module_classes:
                        nn_module_classes.add(cname)
                        break
    # Also add classes found in class_map that have forward() method
    for (fname, cname), info in class_map.items():
        if "forward" in info["methods"]:
            nn_module_classes.add(cname)

    # Per-class attr->class mapping. We scan ALL methods (not just __init__) because
    # some codebases lazily build child sub-modules in helper methods (e.g.
    # ``self.revenue_perceiver_module = SeqPerceiver(...)`` inside ``gen_lsf_fc``).
    # We also capture ``setattr(self, name, ClassName(...))`` patterns where the
    # attribute name comes from a runtime variable — such usages cannot be resolved
    # to a literal attr name, so we synthesise one from the class to keep the child
    # connected (group_<ClassName>).
    class_attrs = {}  # {class_name: {attr_name: class_ref}}
    # Per-(class, attr) source location: {(cname, attr_name): (fname, lineno)}
    attr_def_loc = {}
    # Track attrs that are LG input sources (LG.feature_column/dense_feature/get_sample_rate/get_bias)
    input_source_attrs = defaultdict(set)  # {class_name: {attr_name, ...}}

    # ModuleList/ModuleDict 子模块展开：
    # - container_elems[cname][container_attr] = ["layers[0]", "layers[1]", ...] / ["loss_fns['ctr0']", ...]
    # - 这些 elem_attr 会额外写入 attrs 中，保证 DAG 里出现真实子模块节点。
    container_elems = defaultdict(lambda: defaultdict(list))

    def _normalize_str_key(expr: str):
        expr = (expr or '').strip()
        m = re.match(r"^([\"\'])(.*)\1$", expr)
        if not m:
            return None
        return m.group(2)

    def _elem_attr_list(container: str, idx: int) -> str:
        return f"{container}[{idx}]"

    def _elem_attr_dict(container: str, key: str) -> str:
        # 统一使用单引号，便于稳定匹配
        key = key.replace("'", "\\'")
        return f"{container}['{key}']"

    def _ensure_elem(container: str, cname: str, elem_attr: str, cls_ref: str, fname: str, lineno: int, attrs: dict):
        if elem_attr not in attrs:
            attrs[elem_attr] = cls_ref
            attr_def_loc.setdefault((cname, elem_attr), (fname, lineno))
        if elem_attr not in container_elems[cname][container]:
            container_elems[cname][container].append(elem_attr)

    def _split_top_level_commas(s: str):
        """把 `a(b, c), d, {'k': e}` 按顶层逗号切分。"""
        parts = []
        buf = []
        depth = 0
        in_str = None
        esc = False
        for ch in s:
            if in_str:
                buf.append(ch)
                if esc:
                    esc = False
                elif ch == '\\':
                    esc = True
                elif ch == in_str:
                    in_str = None
                continue
            if ch in ("'", '"'):
                in_str = ch
                buf.append(ch)
                continue
            if ch in '([{':
                depth += 1
            elif ch in ')]}':
                depth = max(0, depth - 1)
            if ch == ',' and depth == 0:
                p = ''.join(buf).strip()
                if p:
                    parts.append(p)
                buf = []
            else:
                buf.append(ch)
        last = ''.join(buf).strip()
        if last:
            parts.append(last)
        return parts

    def _parse_list_ctor_items(list_inner: str):
        items = []
        for p in _split_top_level_commas(list_inner):
            m = re.match(r'^\s*([\w.]+)\s*\(', p)
            if m:
                items.append(m.group(1).split('.')[-1])
        return items

    def _parse_dict_ctor_items(dict_inner: str):
        items = []
        # 顶层按逗号切，顶层按第一个冒号切
        for p in _split_top_level_commas(dict_inner):
            # split key:value
            depth = 0
            in_str = None
            esc = False
            split_i = None
            for i, ch in enumerate(p):
                if in_str:
                    if esc:
                        esc = False
                    elif ch == '\\':
                        esc = True
                    elif ch == in_str:
                        in_str = None
                    continue
                if ch in ("'", '"'):
                    in_str = ch
                    continue
                if ch in '([{':
                    depth += 1
                elif ch in ')]}':
                    depth = max(0, depth - 1)
                if ch == ':' and depth == 0:
                    split_i = i
                    break
            if split_i is None:
                continue
            k_expr = p[:split_i].strip()
            v_expr = p[split_i + 1:].strip()
            k = _normalize_str_key(k_expr)
            if not k:
                continue
            m = re.match(r'^\s*([\w.]+)\s*\(', v_expr)
            if not m:
                continue
            items.append((k, m.group(1).split('.')[-1]))
        return items
    for (fname, cname), info in class_map.items():
        if cname not in nn_module_classes:
            continue
        lines = source_files.get(fname, [])
        attrs = {}

        # Scan every method body for module assignments
        for mname, (ms, me) in info["methods"].items():
            method_lines = lines[ms - 1: min(me, len(lines))]
            # Track absolute line numbers per joined logical line by storing the
            # index of the first physical line that contributed to it.
            logical_lines = []
            buf = ""
            buf_start_lineno = None
            open_count = 0
            for offset, line in enumerate(method_lines):
                phys_lineno = ms + offset
                stripped = line.strip()
                if not stripped or stripped.startswith('#'):
                    if not buf:
                        logical_lines.append((phys_lineno, line))
                    continue
                if not buf:
                    buf_start_lineno = phys_lineno
                stripped_nc = _strip_inline_comment(stripped).strip()
                if not stripped_nc:
                    # 这一行去掉注释后为空
                    continue
                buf += (" " if buf else "") + stripped_nc
                open_count += stripped_nc.count('(') + stripped_nc.count('[') + stripped_nc.count('{')
                open_count -= stripped_nc.count(')') + stripped_nc.count(']') + stripped_nc.count('}')
                if open_count <= 0:
                    logical_lines.append((buf_start_lineno, buf))
                    buf = ""
                    buf_start_lineno = None
                    open_count = 0
            if buf:
                logical_lines.append((buf_start_lineno, buf))

            for phys_lineno, line in logical_lines:
                # 尝试从调用点提取构造参数里的 int 常量（用于后续 ModuleList(range(N)) 展开）
                # 仅采集 `self.xxx = ClassName(... kw=INT/CONST ...)` 这种直接 new。
                m_ctor = re.match(r'\s*self\.(\w+)\s*=\s*([\w.]+)\((.*)\)\s*$', line)
                if m_ctor:
                    _cls_full = m_ctor.group(2)
                    _cls = _cls_full.split('.')[-1]
                    if _cls:
                        for k, v in _extract_kw_int_args(m_ctor.group(3), fname).items():
                            ctor_kw_int_args[_cls][k].add(v)

                # Direct assignment: self.xxx = ClassName(...)
                m = re.match(r'\s*self\.(\w+)\s*=\s*([\w.]+)\(', line)
                if m:
                    attr_name, cls_ref_full = m.groups()
                    cls_ref = cls_ref_full.split('.')[-1]
                    if cls_ref in nn_module_classes:
                        attrs[attr_name] = cls_ref
                        attr_def_loc.setdefault((cname, attr_name), (fname, phys_lineno))
                    else:
                        # Detect LG input source modules:
                        # LG.feature_column(...), LG.dense_feature(...),
                        # LG.get_sample_rate(...), LG.get_bias(...)
                        _lg_m = re.match(
                            r'\s*self\.(\w+)\s*=\s*LG\.(feature_column|dense_feature|get_sample_rate|get_bias)\s*\(',
                            line)
                        if _lg_m:
                            attr_name = _lg_m.group(1)
                            attrs[attr_name] = "__LG_InputSource"
                            attr_def_loc.setdefault((cname, attr_name), (fname, phys_lineno))
                            input_source_attrs[cname].add(attr_name)

                # Detect fc_dict[...].get_vector(...) assigned to self.xxx
                # Pattern: self.xxx = fc_dict[slot].get_vector(...) or similar
                _fc_gv_m = re.match(
                    r'\s*self\.(\w+)\s*=\s*\w+(?:_dict|_fc)?\w*\[.*?\]\.get_vector\s*\(', line)
                if _fc_gv_m:
                    attr_name = _fc_gv_m.group(1)
                    if attr_name not in attrs:
                        attrs[attr_name] = "__LG_InputSource"
                        attr_def_loc.setdefault((cname, attr_name), (fname, phys_lineno))
                        input_source_attrs[cname].add(attr_name)

                # ModuleList / ModuleDict direct construction with literals:
                #   self.xx = nn.ModuleList([A(...), B(...)])
                #   self.xx = nn.ModuleDict({'k': A(...), ...})
                # 说明：完全动态（推导式/变量 key）场景会在后续 append / setitem 路径上补一个 [*]。
                m_ml_lit = re.match(r'\s*self\.(\w+)\s*=\s*[\w.]*ModuleList\(\s*\[(.*)\]\s*\)\s*$', line)
                if m_ml_lit:
                    cont = m_ml_lit.group(1)
                    inner = m_ml_lit.group(2)
                    # 推导式： [Cls(...) for _ in range(N)]
                    m_comp = re.search(r'^\s*([\w.]+)\s*\(.*\)\s*for\s+\w+\s+in\s+range\(\s*([A-Z][A-Z0-9_]*|\d+)\s*\)\s*$', inner)
                    if m_comp:
                        cls_ref = m_comp.group(1).split('.')[-1]
                        n = _eval_int_atom(m_comp.group(2), fname)
                        if n is not None and cls_ref in nn_module_classes:
                            # 保留基线行为：container 仍映射到该类
                            attrs.setdefault(cont, cls_ref)
                            attr_def_loc.setdefault((cname, cont), (fname, phys_lineno))
                            for i in range(n):
                                _ensure_elem(cont, cname, _elem_attr_list(cont, i), cls_ref, fname, phys_lineno, attrs)
                    else:
                        for i, cls_ref in enumerate(_parse_list_ctor_items(inner)):
                            if cls_ref in nn_module_classes:
                                attrs.setdefault(cont, cls_ref)
                                attr_def_loc.setdefault((cname, cont), (fname, phys_lineno))
                                _ensure_elem(cont, cname, _elem_attr_list(cont, i), cls_ref, fname, phys_lineno, attrs)

                m_md_lit = re.match(r'\s*self\.(\w+)\s*=\s*[\w.]*ModuleDict\(\s*\{(.*)\}\s*\)\s*$', line)
                if m_md_lit:
                    cont = m_md_lit.group(1)
                    inner = m_md_lit.group(2)
                    for k, cls_ref in _parse_dict_ctor_items(inner):
                        if cls_ref in nn_module_classes:
                            attrs.setdefault(cont, cls_ref)
                            attr_def_loc.setdefault((cname, cont), (fname, phys_lineno))
                            _ensure_elem(cont, cname, _elem_attr_dict(cont, k), cls_ref, fname, phys_lineno, attrs)
                # ModuleList append: self.xxx.append(ClassName(...))
                m2 = re.search(r'self\.(\w+)\.append\(\s*([\w.]+)\(', line)
                if m2:
                    attr_name, cls_ref_full = m2.groups()
                    cls_ref = cls_ref_full.split('.')[-1]
                    if cls_ref in nn_module_classes:
                        # 保留基线：container 名仍映射到子类
                        attrs[attr_name] = cls_ref
                        attr_def_loc.setdefault((cname, attr_name), (fname, phys_lineno))
                        # 追加展开：container[idx]
                        idx = len(container_elems[cname][attr_name])
                        _ensure_elem(attr_name, cname, _elem_attr_list(attr_name, idx), cls_ref, fname, phys_lineno, attrs)
                # ModuleDict / list assignment: self.xxx[key] = ClassName(...)
                m3 = re.match(r'\s*self\.(\w+)\[\s*([^\]]+?)\s*\]\s*=\s*([\w.]+)\(', line)
                if m3:
                    attr_name, key_expr, cls_ref_full = m3.groups()
                    cls_ref = cls_ref_full.split('.')[-1]
                    if cls_ref in nn_module_classes:
                        attrs[attr_name] = cls_ref
                        attr_def_loc.setdefault((cname, attr_name), (fname, phys_lineno))
                        k = _normalize_str_key(key_expr)
                        if k is not None:
                            _ensure_elem(attr_name, cname, _elem_attr_dict(attr_name, k), cls_ref, fname, phys_lineno, attrs)
                        else:
                            # 动态 key：补一个通配节点，保证 forward 的依赖能连上
                            _ensure_elem(attr_name, cname, f"{attr_name}[*]", cls_ref, fname, phys_lineno, attrs)
                # setattr(self, name_var_or_literal, ClassName(...))
                # - If name is a literal string, register the real attr name.
                # - Otherwise, register a synthetic attr ``__setattr_<ClassName>`` so the child class
                #   is at least connected in the DAG (dynamic names will be resolved at call sites).
                m4 = re.search(r'setattr\(\s*self\s*,\s*([^,]+?)\s*,\s*([\w.]+)\(', line)
                if m4:
                    name_expr = m4.group(1).strip()
                    cls_ref_full = m4.group(2)
                    cls_ref = cls_ref_full.split('.')[-1]
                    if cls_ref in nn_module_classes:
                        # name literal: 'xxx' / "xxx" / f'xxx'(no {}) / f"xxx"(no {})
                        real_attr = None
                        m_lit = re.match(r"^[fF]?[\"\']([^\"\']+)[\"\']$", name_expr)
                        if m_lit:
                            s = m_lit.group(1)
                            # If it's an f-string with interpolation, keep dynamic
                            if '{' not in name_expr and '}' not in name_expr:
                                real_attr = s
                        if real_attr:
                            attrs[real_attr] = cls_ref
                            attr_def_loc.setdefault((cname, real_attr), (fname, phys_lineno))
                        else:
                            synth_attr = f"__setattr_{cls_ref}"
                            # Only register if no real literal attr already maps to this class
                            if synth_attr not in attrs and not any(v == cls_ref for v in attrs.values()):
                                attrs[synth_attr] = cls_ref
                                attr_def_loc.setdefault((cname, synth_attr), (fname, phys_lineno))
        class_attrs[cname] = attrs

    # ------------------------------------------------------------------
    # 二次扫描（保守增强）：识别 range(N) 循环中的 `var = ClassName(...)` + `self.list.append(var)`
    # 用于展开像 Transformer.resblocks 这种“先构造到局部变量再 append”的写法。
    # 仅当 N 可解析为 int 时展开为 N 个 [i] 节点；解析失败则不影响基线（仍保留 container 映射）。
    # ------------------------------------------------------------------
    _FOR_RANGE_RE = re.compile(r'^(\s*)for\s+\w+\s+in\s+range\(\s*([^\)]+)\s*\)\s*:\s*$')
    _ASSIGN_CTOR_RE = re.compile(r'^\s*(\w+)\s*=\s*([\w.]+)\s*\(')
    _APPEND_VAR_RE = re.compile(r'^\s*self\.(\w+)\.append\(\s*(\w+)\s*\)')
    _SELF_SET_RE = re.compile(r'^\s*self\.(\w+)\s*=\s*(\w+)\s*$')

    def _resolve_range_n(expr: str, fname: str, cname: str, self_to_param: dict, local_vars: dict):
        expr = (expr or '').strip()
        if expr in local_vars and isinstance(local_vars[expr], int):
            return local_vars[expr]
        v = _eval_int_atom(expr, fname)
        if v is not None:
            return v
        # 参数名（如 layers）
        if expr in ctor_kw_int_args.get(cname, {}):
            vals = sorted(ctor_kw_int_args[cname][expr])
            if len(vals) == 1:
                return vals[0]
        # self.xxx -> 参数
        if expr.startswith('self.'):
            an = expr.split('.', 1)[1]
            pn = self_to_param.get(an)
            if pn and pn in ctor_kw_int_args.get(cname, {}):
                vals = sorted(ctor_kw_int_args[cname][pn])
                if len(vals) == 1:
                    return vals[0]
        return None

    for (fname, cname), info in class_map.items():
        if cname not in nn_module_classes:
            continue
        lines = source_files.get(fname, [])
        attrs = class_attrs.get(cname, {})
        # 建立 self.attr = param 的映射（如 self.layers = layers）
        self_to_param = {}
        init_rng = info['methods'].get('__init__')
        if init_rng:
            init_lines = lines[init_rng[0] - 1: min(init_rng[1], len(lines))]
            for ln in init_lines:
                m = _SELF_SET_RE.match(ln)
                if m:
                    self_to_param[m.group(1)] = m.group(2)

        # 扫描各方法，找 for-range 的 append(var)
        for mname, (ms, me) in info['methods'].items():
            method_lines = lines[ms - 1: min(me, len(lines))]
            local_vars = {}
            var_to_cls = {}
            i = 0
            while i < len(method_lines):
                raw = method_lines[i]
                # 记录本地 int 常量：x = 6 / x = CONST
                m_lv = re.match(r'^\s*(\w+)\s*=\s*([A-Z][A-Z0-9_]*|\d+)\s*(?:#.*)?$', raw)
                if m_lv:
                    vv = _eval_int_atom(m_lv.group(2), fname)
                    if vv is not None:
                        local_vars[m_lv.group(1)] = vv

                fm = _FOR_RANGE_RE.match(raw)
                if not fm:
                    i += 1
                    continue
                base_indent = len(fm.group(1))
                range_expr = fm.group(2).strip()
                n = _resolve_range_n(range_expr, fname, cname, self_to_param, local_vars)
                # 扫描 loop body
                j = i + 1
                while j < len(method_lines):
                    body_raw = method_lines[j]
                    if not body_raw.strip():
                        j += 1
                        continue
                    ind = len(body_raw) - len(body_raw.lstrip())
                    if ind <= base_indent:
                        break
                    am = _ASSIGN_CTOR_RE.match(body_raw)
                    if am:
                        vname = am.group(1)
                        cls_ref = am.group(2).split('.')[-1]
                        if cls_ref in nn_module_classes:
                            var_to_cls[vname] = cls_ref
                    ap = _APPEND_VAR_RE.match(body_raw)
                    if ap and n is not None:
                        cont = ap.group(1)
                        vname = ap.group(2)
                        cls_ref = var_to_cls.get(vname)
                        if cls_ref and cls_ref in nn_module_classes:
                            # 保留基线 container
                            attrs.setdefault(cont, cls_ref)
                            attr_def_loc.setdefault((cname, cont), (fname, ms + j))
                            # 展开 N 个 element
                            for k in range(n):
                                _ensure_elem(cont, cname, _elem_attr_list(cont, k), cls_ref, fname, ms + j, attrs)
                    j += 1
                i = j

        class_attrs[cname] = attrs

    # Build data dependency edges between child modules
    dep_edges, dep_edge_locs, split_info = _build_data_dependency_edges(source_files, class_map, class_attrs)

    # Inject split nodes into class_attrs so they appear as DAG nodes.
    # e.g. if GAUBlock has split_info = {"norm": ["norm#0", "norm#1"]},
    # add "norm#0" and "norm#1" to class_attrs["GAUBlock"] with the same class ref as "norm".
    for cname, smap in split_info.items():
        if cname not in class_attrs:
            continue
        for orig_attr, split_names in smap.items():
            cls_ref = class_attrs[cname].get(orig_attr)
            if cls_ref is None:
                continue
            # Remove the original attr from class_attrs (replaced by splits)
            del class_attrs[cname][orig_attr]
            for sn in split_names:
                class_attrs[cname][sn] = cls_ref

    # Build tree using forward() call order + __init__ attrs
    tree = {}
    all_child_classes = set()
    for cname in nn_module_classes:
        if cname not in class_attrs:
            class_attrs[cname] = {}
        attrs = class_attrs[cname]
        call_order = module_call_order.get(cname, [])

        # Order children by forward() call order
        children_ordered = []
        seen = set()
        for attr in call_order:
            if attr in attrs and attrs[attr] not in seen:
                children_ordered.append(attrs[attr])
                seen.add(attrs[attr])
                all_child_classes.add(attrs[attr])
        # Add remaining attrs not called in forward
        for attr, cls_ref in attrs.items():
            if cls_ref not in seen:
                children_ordered.append(cls_ref)
                seen.add(cls_ref)
                all_child_classes.add(cls_ref)

        tree[cname] = {"children": children_ordered, "attrs": attrs,
                       "dep_edges": dep_edges.get(cname, []),
                       "dep_edge_locs": dep_edge_locs.get(cname, {})}

    # Find root(s): classes that are NOT children of any other class
    roots = [c for c in nn_module_classes if c not in all_child_classes and c in tree]
    if not roots:
        roots = list(tree.keys())[:1]

    # Prefer roots that have children (real model roots), sort by descendant count
    def count_descendants(cname, visited=None):
        if visited is None:
            visited = set()
        if cname in visited or cname not in tree:
            return 0
        visited.add(cname)
        total = len(tree[cname]["children"])
        for child in tree[cname]["children"]:
            total += count_descendants(child, visited)
        return total

    roots_with_children = [r for r in roots if tree.get(r, {}).get("children")]
    if roots_with_children:
        roots = sorted(roots_with_children, key=lambda r: -count_descendants(r))
    # If "RootModule" is present, put it first
    if "RootModule" in roots:
        roots = ["RootModule"] + [r for r in roots if r != "RootModule"]
    # Honour caller-supplied preferred root (e.g. derived from timeline wrapper name)
    if preferred_root and preferred_root in roots:
        roots = [preferred_root] + [r for r in roots if r != preferred_root]

    # Filter tree to only include classes reachable from the primary root.
    # This eliminates orphan classes that are defined but never instantiated.
    if roots:
        reachable = set()
        def _collect_reachable(cname):
            if cname in reachable or cname not in tree:
                return
            reachable.add(cname)
            for child in tree[cname].get("children", []):
                _collect_reachable(child)
        for r in roots[:1]:  # Only from primary root
            _collect_reachable(r)
        # Keep only reachable classes in tree, filter roots
        tree = {k: v for k, v in tree.items() if k in reachable}
        roots = [r for r in roots if r in reachable]
        if not roots and reachable:
            roots = sorted(reachable, key=lambda r: -count_descendants(r))[:1]

    # Stash attr definition locations on the tree for downstream consumers
    # (HTML flowchart click-interactions). Format: tree[cname]["attr_def_loc"][attr] = (fname, lineno)
    for cname in tree:
        per_class = {}
        for attr in tree[cname].get("attrs", {}):
            loc = attr_def_loc.get((cname, attr))
            if loc:
                per_class[attr] = loc
        tree[cname]["attr_def_loc"] = per_class

    # Build first_call_loc: first forward() call line for each attr.
    # Strategy 1: derive from dep_edge_locs (edges between siblings).
    # Strategy 2: directly scan forward() for self.attr(...) calls (covers entry/exit-only modules).
    for cname in tree:
        edge_locs_c = tree[cname].get("dep_edge_locs", {})
        first_call = {}  # attr -> (file, lineno)
        for (from_a, to_a), ev in edge_locs_c.items():
            if not isinstance(ev, dict):
                continue
            f = ev.get("file", "")
            if from_a and ev.get("from_line"):
                if from_a not in first_call or ev["from_line"] < first_call[from_a][1]:
                    first_call[from_a] = (f, ev["from_line"])
            if to_a and ev.get("to_line"):
                if to_a not in first_call or ev["to_line"] < first_call[to_a][1]:
                    first_call[to_a] = (f, ev["to_line"])
        # Strategy 2: scan forward() for attrs not yet found
        known_attrs_c = set(tree[cname].get("attrs", {}).keys())
        missing_attrs = known_attrs_c - set(first_call.keys())
        if missing_attrs:
            # For container elements like "ordinal_towers[0]", look for the base container name
            _base_name_map = {}  # base_container_name -> set of element attrs needing it
            _direct_missing = set()
            for a in missing_attrs:
                if '[' in a:
                    base = a.split('[')[0]
                    _base_name_map.setdefault(base, set()).add(a)
                else:
                    _direct_missing.add(a)
            for (fname, cm_name), cm_info in class_map.items():
                if cm_name != cname:
                    continue
                fwd_range = cm_info["methods"].get("forward")
                if not fwd_range:
                    continue
                lines_c = source_files.get(fname, [])
                for i in range(fwd_range[0] - 1, min(fwd_range[1], len(lines_c))):
                    line_text = lines_c[i]
                    phys_ln = i + 1
                    for m_call in re.finditer(r'self\.(\w+)\s*[\(\[]', line_text):
                        a = m_call.group(1)
                        if a in _direct_missing and a not in first_call:
                            first_call[a] = (fname, phys_ln)
                        if a in _base_name_map:
                            for elem_attr in _base_name_map[a]:
                                if elem_attr not in first_call:
                                    first_call[elem_attr] = (fname, phys_ln)
                    for m_ga in re.finditer(r'getattr\(\s*self\s*,\s*["\']([^"\']+)["\']\s*\)', line_text):
                        a = m_ga.group(1)
                        if a in _direct_missing and a not in first_call:
                            first_call[a] = (fname, phys_ln)
                break
        tree[cname]["first_call_loc"] = first_call

    # Stash input_source_attrs on the tree for downstream consumers
    for cname in tree:
        tree[cname]["input_source_attrs"] = input_source_attrs.get(cname, set())

    return tree, roots, class_map


def _build_runtime_module_hierarchy(events):
    """Build module containment hierarchy from trace events.
    Returns: {class_name: {"children": [child_names], "parents": set(parent_names)}}
    """
    mod_events = []
    for e in events:
        name = e.get('name', '')
        if not name.startswith('nn.Module:') or e.get('ph') != 'X':
            continue
        short = name.replace('nn.Module: ', '').replace('nn.Module:', '')
        short = re.sub(r',\s*callsite:\s*\d+', '', short).strip()
        base = re.sub(r'_\d+$', '', short)
        mod_events.append({
            'name': base,
            'ts': e['ts'],
            'dur': e.get('dur', 0),
            'end': e['ts'] + e.get('dur', 0),
            'tid': e.get('tid'),
        })

    parent_child = defaultdict(set)
    child_parent = defaultdict(set)
    all_tids = set(e['tid'] for e in mod_events)
    top_level = set()

    for tid in all_tids:
        tid_events = [e for e in mod_events if e['tid'] == tid]
        tid_events.sort(key=lambda x: (x['ts'], -x['dur']))
        stack = []
        for e in tid_events:
            while stack and stack[-1]['end'] <= e['ts']:
                stack.pop()
            if stack:
                parent_child[stack[-1]['name']].add(e['name'])
                child_parent[e['name']].add(stack[-1]['name'])
            else:
                top_level.add(e['name'])
            stack.append(e)

    hierarchy = {}
    all_names = set(e['name'] for e in mod_events)
    for name in all_names:
        children = sorted(parent_child.get(name, set()))
        parents = child_parent.get(name, set())
        hierarchy[name] = {"children": children, "parents": parents}

    return hierarchy, top_level


def _merge_runtime_into_tree(tree, roots, runtime_hierarchy, runtime_top_level, class_durations):
    """Merge runtime-only modules into the static tree so all timeline modules are connected.
    Runtime modules not in source tree get virtual entries connected via containment edges.
    DDPRootModule -> RootModule connection is established by stripping DDP prefix.
    """
    static_classes = set(tree.keys())
    runtime_classes = set(runtime_hierarchy.keys())
    runtime_only = runtime_classes - static_classes

    if not runtime_only:
        return tree, roots

    # Establish mapping from runtime wrapper to source root
    # DDPRootModule/FSDPRootModule -> RootModule
    wrapper_to_source = {}
    for rmod in runtime_only:
        stripped = re.sub(r'^(FSDP|DDP|DistributedDataParallel|Wrapped)', '', rmod)
        if stripped in static_classes and stripped != rmod:
            wrapper_to_source[rmod] = stripped

    # Add runtime-only modules to tree
    for rmod in runtime_only:
        rinfo = runtime_hierarchy[rmod]
        # Children: only include those that are also runtime-only OR are wrapper targets
        children = []
        attrs = {}
        for child in rinfo["children"]:
            if child in runtime_only or child in wrapper_to_source:
                attr_name = child[0].lower() + child[1:]
                children.append(child)
                attrs[attr_name] = child
            elif child in static_classes:
                attr_name = child[0].lower() + child[1:]
                children.append(child)
                attrs[attr_name] = child

        # If this runtime module wraps a source module, add that as child
        if rmod in wrapper_to_source:
            src_target = wrapper_to_source[rmod]
            if src_target not in children:
                attr_name = src_target[0].lower() + src_target[1:]
                children.append(src_target)
                attrs[attr_name] = src_target

        # Build sequential dep edges (runtime modules are pipeline-sequential)
        dep_edges = []
        attr_names_ordered = list(attrs.keys())
        for i in range(len(attr_names_ordered) - 1):
            dep_edges.append((attr_names_ordered[i], attr_names_ordered[i + 1]))

        tree[rmod] = {"children": children, "attrs": attrs, "dep_edges": dep_edges,
                       "dep_edge_locs": {}, "attr_def_loc": {}}

    # Determine new roots: runtime top-level modules that contain everything
    # Prefer a single root that encompasses all others
    new_roots = []
    # Find the broadest runtime top-level module (most descendants)
    def count_rt_descendants(name, visited=None):
        if visited is None:
            visited = set()
        if name in visited or name not in tree:
            return 0
        visited.add(name)
        total = len(tree[name]["children"])
        for child in tree[name]["children"]:
            total += count_rt_descendants(child, visited)
        return total

    # Runtime top-level modules become candidate roots
    rt_roots = [r for r in runtime_top_level if r in tree]
    if rt_roots:
        rt_roots_sorted = sorted(rt_roots, key=lambda r: -count_rt_descendants(r))
        # All runtime top-level modules are roots (they are independent execution units)
        new_roots = list(rt_roots_sorted)
        # Check reachability from all runtime roots
        reachable = set()
        def collect_reachable(name, visited):
            if name in visited or name not in tree:
                return
            visited.add(name)
            reachable.add(name)
            for child in tree[name]["children"]:
                collect_reachable(child, visited)
        for rr in rt_roots:
            collect_reachable(rr, set())

        # Add source roots that are NOT reachable from any runtime root
        for sr in roots:
            if sr not in reachable:
                new_roots.append(sr)
    else:
        new_roots = roots

    return tree, new_roots


def _validate_timeline_modules(trace_events, tree):
    """Validate that all user model nn.Module classes in timeline are present in the DAG tree.
    Runtime wrapper modules (not in user source) are expected to be absent.
    Returns validation info dict.
    """
    if not trace_events:
        return None

    timeline_modules = set()
    for e in trace_events:
        name = e.get('name', '')
        if not name.startswith('nn.Module:') or e.get('ph') != 'X':
            continue
        short = name.replace('nn.Module: ', '').replace('nn.Module:', '')
        short = re.sub(r',\s*callsite:\s*\d+', '', short).strip()
        base = re.sub(r'_\d+$', '', short)
        timeline_modules.add(base)

    if not timeline_modules:
        return None

    tree_classes = set(tree.keys())
    # Timeline modules that ARE in the source tree (user model modules)
    in_tree = timeline_modules & tree_classes
    # Timeline modules that are NOT in source tree (runtime wrappers)
    runtime_only = timeline_modules - tree_classes

    # Check connectivity: all tree classes should be reachable from root via dep_edges or children
    connected = set()
    def _check_connected(cname, visited=None):
        if visited is None:
            visited = set()
        if cname in visited or cname not in tree:
            return
        visited.add(cname)
        connected.add(cname)
        for child in tree[cname].get("children", []):
            _check_connected(child, visited)
    for root in tree_classes:
        if root not in [c for info in tree.values() for c in info.get("children", [])]:
            _check_connected(root)

    validation = {
        "timeline_total": len(timeline_modules),
        "in_source_tree": sorted(in_tree),
        "runtime_wrappers": sorted(runtime_only),
        "tree_classes": sorted(tree_classes),
        "connected_classes": sorted(connected),
        "all_connected": tree_classes == connected,
    }

    # Print validation summary
    print(f"  📋 Timeline nn.Module 验证:")
    print(f"     Timeline 中共 {len(timeline_modules)} 个 Module 类")
    if in_tree:
        print(f"     ✅ 用户模型 Module (在 DAG 中): {sorted(in_tree)}")
    if runtime_only:
        print(f"     ℹ️  运行时 wrapper Module (不在用户源码中, 无需加入 DAG): {len(runtime_only)} 个")
    disconnected = tree_classes - connected
    if disconnected:
        print(f"     ⚠️  DAG 中未连接的类: {sorted(disconnected)}")
    else:
        print(f"     ✅ DAG 中所有 {len(tree_classes)} 个源码 Module 类均已正确连接")

    # Cross-check: any timeline module that has the same name as a source nn.Module
    # MUST also exist in the DAG tree. If a class is defined in user source but
    # filtered out of the tree (e.g. because the wrong root was picked), surface it
    # as a validation failure so the caller can iterate.
    # We re-load the full nn_module_classes list from class_map by inspecting the
    # tree's union with whatever we know. For a stricter check the caller should
    # have already used preferred_root logic.
    user_source_in_timeline_missing = []
    # We can only detect this with extra info; not done here to avoid import churn.
    # Validation output above is the authoritative pass/fail summary.

    return validation


def generate_html_flowchart(source_files, timing_data=None, meta=None, output_path="flowchart.html", trace_events=None):
    """Generate interactive DAG HTML flowchart with expandable nested modules.

    Top-level layout is fixed as: Input -> RootModule -> Result.
    All other nn.Module sub-modules live INSIDE the RootModule container, linked
    by data dependency edges (extracted from forward()). Runtime wrapper modules
    such as DDPRootModule / SyncModule / SequentialModule / RunstepModule are
    intentionally NOT shown at the top level — they are treated as transparent
    wrappers around RootModule.

    Args:
        source_files: dict of {filename: [lines]} from load_model_code()
        timing_data: optional dict with timing info from trace analysis
        meta: optional metadata dict
        output_path: HTML output file path
        trace_events: optional list of trace events for runtime hierarchy extraction
            (kept for API compatibility — used only for timing fallbacks, NOT for
            adding wrapper modules to the DAG)

    Interactive features baked into the resulting HTML:
        * Clicking a leaf node or an expanded group header opens a side panel
          showing the class definition with file path and line range.
        * Clicking a data dependency edge opens a side panel showing the actual
          forward() lines that produced and consumed the tensor variable.
    """
    # When we have timeline events, derive a hint for which top-level user model
    # to use as the DAG root by stripping common DDP/FSDP prefixes from runtime
    # wrapper module names.
    preferred_root = None
    if trace_events:
        runtime_names = set()
        for e in trace_events:
            n = e.get('name', '')
            if not n.startswith('nn.Module:') or e.get('ph') != 'X':
                continue
            short = n.replace('nn.Module: ', '').replace('nn.Module:', '')
            short = re.sub(r',\s*callsite:\s*\d+', '', short).strip()
            runtime_names.add(re.sub(r'_\d+$', '', short))
        # Strip wrapper prefixes and look for matches in source classes
        for wrapper_prefixes in [r'^DDP', r'^FSDP', r'^DistributedDataParallel', r'^Wrapped']:
            for rn in runtime_names:
                stripped = re.sub(wrapper_prefixes, '', rn)
                if stripped != rn and stripped:
                    preferred_root = stripped
                    break
            if preferred_root:
                break

    tree, roots, class_map = build_static_module_tree(source_files, preferred_root=preferred_root)

    if not tree:
        print("  ⚠️ 未在源码中检测到 nn.Module 子类，无法生成流程图")
        return None

    # Validate timeline modules against the DAG tree
    _validate_timeline_modules(trace_events, tree)

    # Force top-level root to RootModule. All sub-modules will live inside it.
    # Runtime wrappers (DDPRootModule, SyncModule, ...) are intentionally hidden.
    if "RootModule" in tree:
        roots = ["RootModule"]
    else:
        # Fall back to the previously detected primary root (single root only)
        roots = roots[:1] if roots else []

    has_timing = timing_data is not None and timing_data.get("step_dur_us", 0) > 0
    step_dur_us = timing_data["step_dur_us"] if has_timing else 0
    class_durations = timing_data.get("class_durations", {}) if has_timing else {}
    class_durations_fwd = timing_data.get("class_durations_fwd", {}) if has_timing else {}
    class_durations_bwd = timing_data.get("class_durations_bwd", {}) if has_timing else {}
    class_exclusive = timing_data.get("class_exclusive", {}) if has_timing else {}
    class_calls = timing_data.get("class_calls", {}) if has_timing else {}
    class_thread_role = timing_data.get("class_thread_role", {}) if has_timing else {}

    # ------------------------------------------------------------------
    # Iter7: the top-level output node is the synthetic Result object created
    # by LG.result() inside RootModule.forward(). It is NOT a hoisted
    # nn.Module child, so we must keep all root attrs inside the RootModule
    # container and derive Result edges from actual result.head()/return lines.
    # ------------------------------------------------------------------
    loss_attr_name = None
    loss_class_name = None

    # ------------------------------------------------------------------
    # Build class source-location lookup for click-to-source UX.
    # For each class, we record:
    #   - file: defining filename
    #   - start_line / end_line: class definition range
    #   - snippet_start / snippet_end: a trimmed snippet bounded around __init__/forward
    #   - snippet: the actual text lines (capped to ~120 lines for transport size)
    # ------------------------------------------------------------------
    _SNIPPET_MAX_LINES = 160
    class_source_info = {}
    for (fname, cname), info in class_map.items():
        if cname not in tree:
            continue
        start = info["start"]
        end = info["end"]
        lines = source_files.get(fname, [])
        # Pick a focused snippet: prefer the smaller of (full class) or (~SNIPPET_MAX_LINES from start)
        snippet_end = min(end, start + _SNIPPET_MAX_LINES - 1)
        snippet_lines = lines[start - 1: snippet_end]
        # Keep an overall ceiling to avoid bloating HTML for huge classes
        truncated = snippet_end < end
        class_source_info[cname] = {
            "file": fname,
            "start_line": start,
            "end_line": end,
            "snippet_start": start,
            "snippet_end": snippet_end,
            "snippet": "\n".join(snippet_lines),
            "truncated": truncated,
            "method_ranges": {m: list(r) for m, r in info["methods"].items()},
        }

    def _split_top_level_items(text):
        items = []
        buf = []
        depth = 0
        in_str = None
        esc = False
        for ch in text:
            if in_str:
                buf.append(ch)
                if esc:
                    esc = False
                elif ch == '\\':
                    esc = True
                elif ch == in_str:
                    in_str = None
                continue
            if ch in ("'", '"'):
                in_str = ch
                buf.append(ch)
                continue
            if ch in '([{':
                depth += 1
            elif ch in ')]}':
                depth = max(0, depth - 1)
            if ch == ',' and depth == 0:
                part = ''.join(buf).strip()
                if part:
                    items.append(part)
                buf = []
            else:
                buf.append(ch)
        tail = ''.join(buf).strip()
        if tail:
            items.append(tail)
        return items

    def _parse_call_kwargs(args_text):
        kwargs = {}
        for item in _split_top_level_items(args_text):
            depth = 0
            in_str = None
            esc = False
            split_i = None
            for i, ch in enumerate(item):
                if in_str:
                    if esc:
                        esc = False
                    elif ch == '\\':
                        esc = True
                    elif ch == in_str:
                        in_str = None
                    continue
                if ch in ("'", '"'):
                    in_str = ch
                    continue
                if ch in '([{':
                    depth += 1
                elif ch in ')]}':
                    depth = max(0, depth - 1)
                if ch == '=' and depth == 0:
                    prev_ch = item[i - 1] if i > 0 else ''
                    next_ch = item[i + 1] if i + 1 < len(item) else ''
                    if prev_ch not in ('=', '!', '<', '>') and next_ch != '=':
                        split_i = i
                        break
            if split_i is not None:
                kwargs[item[:split_i].strip()] = item[split_i + 1:].strip()
        return kwargs

    def _scan_root_result_edges(root_cname):
        if not root_cname:
            return {}
        attrs = tree.get(root_cname, {}).get("attrs", {})
        known_attrs = set(attrs.keys())
        if not known_attrs:
            return {}

        container_to_elems = defaultdict(list)
        for a in known_attrs:
            m = re.match(r'^(\w+)\[(.+)\]$', a)
            if m:
                container_to_elems[m.group(1)].append(a)
        for cont in list(container_to_elems.keys()):
            elems = container_to_elems[cont]
            num_elems = []
            other = []
            for ea in elems:
                mm = re.match(r'^' + re.escape(cont) + r'\[(\d+)\]$', ea)
                if mm:
                    num_elems.append((int(mm.group(1)), ea))
                else:
                    other.append(ea)
            if num_elems and not other:
                container_to_elems[cont] = [ea for _, ea in sorted(num_elems)]
            else:
                container_to_elems[cont] = sorted(elems)

        def _norm_index_expr(idx_expr):
            idx_expr = (idx_expr or '').strip()
            if re.fullmatch(r'\d+', idx_expr):
                return str(int(idx_expr))
            m = re.match(r"^([\"\'])(.*)\1$", idx_expr)
            if m:
                return "'" + m.group(2).replace("'", "\\'") + "'"
            return None

        def _resolve_indexed_attr(container, idx_expr):
            norm = _norm_index_expr(idx_expr)
            if norm is not None:
                cand = f"{container}[{norm}]"
                if cand in known_attrs:
                    return [cand]
            if container in container_to_elems and container_to_elems[container]:
                return list(container_to_elems[container])
            return [container] if container in known_attrs else []

        def _collect_direct_module_producers(expr, lineno):
            producers = set()
            best_line = None
            best_var = None
            for m in re.finditer(r'self\.(\w+)\[\s*([^\]]+?)\s*\]\s*\(', expr):
                cont = m.group(1)
                if cont in known_attrs:
                    resolved = _resolve_indexed_attr(cont, m.group(2))
                    for a in resolved:
                        if a in known_attrs:
                            producers.add(a)
                            best_line = lineno
                            best_var = f"self.{a}(...)"
            for m in re.finditer(r'self\.(\w+)\s*\(', expr):
                a = m.group(1)
                if a in known_attrs:
                    producers.add(a)
                    best_line = lineno
                    best_var = f"self.{a}(...)"
            for m in re.finditer(r'getattr\(\s*self\s*,\s*[\"\']([^\"\']+)[\"\']\s*\)\s*\(', expr):
                a = m.group(1)
                if a in known_attrs:
                    producers.add(a)
                    best_line = lineno
                    best_var = f"getattr(self, '{a}')(...)"
            return producers, best_line, best_var

        def _collect_expr_output_producers(expr, var_producers, lineno):
            producers = set()
            best_line = None
            best_var = None
            for var, (ps, ploc) in var_producers.items():
                if re.search(r'\b' + re.escape(var) + r'\b', expr):
                    producers.update(ps)
                    if ploc is not None and (best_line is None or ploc > best_line):
                        best_line = ploc
                        best_var = var
            dps, dline, dvar = _collect_direct_module_producers(expr, lineno)
            if dps:
                producers.update(dps)
                if dline is not None and (best_line is None or dline > best_line):
                    best_line = dline
                    best_var = dvar
            return producers, best_line, best_var

        def _join_lines_local(raw_lines, base_lineno):
            logical = []
            buf = ""
            buf_start = None
            open_count = 0
            for offset, raw in enumerate(raw_lines):
                phys_lineno = base_lineno + offset
                stripped = raw.strip()
                if not stripped or stripped.startswith('#'):
                    if not buf:
                        logical.append((phys_lineno, raw))
                    continue
                if not buf:
                    buf_start = phys_lineno
                stripped_nc = _strip_inline_comment(stripped).strip()
                if not stripped_nc:
                    continue
                buf += (" " if buf else "") + stripped_nc
                open_count += stripped_nc.count('(') + stripped_nc.count('[') + stripped_nc.count('{')
                open_count -= stripped_nc.count(')') + stripped_nc.count(']') + stripped_nc.count('}')
                if open_count <= 0:
                    logical.append((buf_start, buf))
                    buf = ""
                    buf_start = None
                    open_count = 0
            if buf:
                logical.append((buf_start, buf))
            return logical

        result_edges = {}
        for (fname, cname), info in class_map.items():
            if cname != root_cname:
                continue
            fwd_range = info["methods"].get("forward")
            if not fwd_range:
                continue
            lines = source_files.get(fname, [])
            logical_lines = _join_lines_local(lines[fwd_range[0] - 1: min(fwd_range[1], len(lines))], fwd_range[0])
            var_producers = {}
            result_vars = set()

            def _remember(attr, to_line, var_name, from_line=None):
                if attr not in known_attrs:
                    return
                prev = result_edges.get(attr)
                candidate = {
                    "file": fname,
                    "var": var_name,
                    "from_line": from_line if from_line is not None else to_line,
                    "to_line": to_line,
                }
                if prev is None or candidate["to_line"] < prev["to_line"]:
                    result_edges[attr] = candidate

            for phys_lineno, raw_line in logical_lines:
                line = _strip_inline_comment(raw_line).strip()
                if not line or line.startswith('#'):
                    continue

                m_res = re.match(r'^(\w+)\s*=\s*LG\.result\(\)\s*$', line)
                if m_res:
                    result_vars.add(m_res.group(1))
                    continue

                called_attrs = []
                for m in re.finditer(r'self\.(\w+)\[\s*([^\]]+?)\s*\]\s*\(', line):
                    cont = m.group(1)
                    if cont in known_attrs:
                        for a in _resolve_indexed_attr(cont, m.group(2)):
                            if a in known_attrs:
                                called_attrs.append(a)
                for m in re.finditer(r'self\.(\w+)\s*\(', line):
                    a = m.group(1)
                    if a in known_attrs:
                        called_attrs.append(a)
                for m in re.finditer(r'getattr\(\s*self\s*,\s*[\"\']([^\"\']+)[\"\']\s*\)\s*\(', line):
                    a = m.group(1)
                    if a in known_attrs:
                        called_attrs.append(a)
                called_attrs = list(dict.fromkeys(called_attrs))

                tuple_assign = re.match(r'^\(?\s*(\w+(?:\s*,\s*\w+)+)\s*\)?\s*=\s*(.+)$', line)
                if tuple_assign and called_attrs:
                    lhs_vars = [v.strip() for v in tuple_assign.group(1).split(',') if v.strip() and v.strip() != '_']
                    producers = set(called_attrs)
                    for v in lhs_vars:
                        var_producers[v] = (set(producers), phys_lineno)
                else:
                    assign_m = re.match(r'^(\w+)\s*=\s*(.+)$', line)
                    if assign_m:
                        lhs = assign_m.group(1)
                        rhs = assign_m.group(2)
                        if called_attrs:
                            var_producers[lhs] = (set(called_attrs), phys_lineno)
                        else:
                            rhs_prod, rhs_line, _rhs_var = _collect_expr_output_producers(rhs, var_producers, phys_lineno)
                            if rhs_prod:
                                var_producers[lhs] = (rhs_prod, rhs_line if rhs_line is not None else phys_lineno)

                if result_vars:
                    for rv in list(result_vars):
                        head_token = f"{rv}.head("
                        if head_token in line:
                            start = line.index(head_token) + len(head_token)
                            depth = 1
                            end = start
                            for i in range(start, len(line)):
                                if line[i] == '(':
                                    depth += 1
                                elif line[i] == ')':
                                    depth -= 1
                                    if depth == 0:
                                        end = i
                                        break
                            kwargs = _parse_call_kwargs(line[start:end])
                            for kw in ("prediction", "loss"):
                                expr = kwargs.get(kw)
                                if not expr:
                                    continue
                                prod, prod_line, prod_var = _collect_expr_output_producers(expr, var_producers, phys_lineno)
                                for p in prod:
                                    _remember(p, phys_lineno, prod_var or expr, prod_line)

                ret_m = re.match(r'^return\s+(.+)$', line)
                if ret_m and result_vars:
                    ret_parts = _split_top_level_items(ret_m.group(1))
                    if len(ret_parts) >= 2 and ret_parts[0].strip() in result_vars:
                        loss_expr = ret_parts[1].strip()
                        prod, prod_line, prod_var = _collect_expr_output_producers(loss_expr, var_producers, phys_lineno)
                        for p in prod:
                            _remember(p, phys_lineno, prod_var or loss_expr, prod_line)
            break
        return result_edges

    # Build DAG data: each usage instance is a separate node
    # A DAG node represents one attr usage in a parent's forward()
    dag_nodes = []
    dag_edges = []
    dag_groups = []  # nested container groups
    counter = [0]
    # Pre-compute forward call order once
    _module_call_order, _ = _build_source_dependency_order(source_files, class_map)

    def new_id():
        counter[0] += 1
        return f"node_{counter[0]}"

    def build_dag_recursive(cname, parent_path, depth, max_depth=10):
        """Build DAG nodes for class cname. Returns the group descriptor."""
        if depth >= max_depth or cname not in tree:
            return None
        info = tree[cname]
        children_classes = info["children"]
        attrs = info.get("attrs", {})
        dep_edge_list = info.get("dep_edges", [])

        # Remove container attrs (nn.ModuleDict/ModuleList containers) from the
        # DAG. Containers are NOT real graph nodes — only their expanded elements
        # participate in data flow. When a dep_edge references a container, remap
        # it to the container's element(s).
        _elem_re_local = re.compile(r'^(\w+)\[.+\]$')
        _containers_with_elems = set()
        for a in attrs:
            m = _elem_re_local.match(a)
            if m:
                _containers_with_elems.add(m.group(1))
        # Only filter containers that actually have expanded elements in attrs
        _containers_to_remove = set(c for c in _containers_with_elems if c in attrs)
        # Build container → elements mapping for edge remapping
        _container_to_elems_local = defaultdict(list)
        for a in attrs:
            m = _elem_re_local.match(a)
            if m and m.group(1) in _containers_to_remove:
                _container_to_elems_local[m.group(1)].append(a)

        # Also remove __LG_InputSource attrs from DAG node creation.
        # They represent network inputs (LG.feature_column / LG.dense_feature),
        # not real nn.Module DAG nodes. Their edges are remapped: if an LG source
        # feeds a real module, that real module receives from Input instead.
        _lg_source_attrs = set(a for a, c in attrs.items() if c == "__LG_InputSource")

        attrs_filtered = {a: c for a, c in attrs.items()
                          if a not in _containers_to_remove and a not in _lg_source_attrs}

        # Remap dep_edges: replace container references with element references
        _remapped_dep_edges = []
        # Also collect edges from LG sources to real modules (for Input connection)
        _input_consumer_edges = []  # [(to_attr, evidence_key)]
        for (fa, ta) in dep_edge_list:
            # If source is an LG input, the target consumes Input directly
            if fa in _lg_source_attrs:
                if ta not in _lg_source_attrs and ta not in _containers_to_remove:
                    _input_consumer_edges.append((fa, ta))
                continue
            # If target is an LG input, skip (shouldn't happen but guard)
            if ta in _lg_source_attrs:
                continue
            froms = _container_to_elems_local.get(fa, [fa])
            tos = _container_to_elems_local.get(ta, [ta])
            for f in froms:
                for t in tos:
                    if f != t and f in attrs_filtered and t in attrs_filtered:
                        _remapped_dep_edges.append((f, t))
        dep_edge_list = list(set(_remapped_dep_edges))

        # Reverse map: class -> list of attr names
        cls_to_attrs = defaultdict(list)
        for attr, cls_ref in attrs_filtered.items():
            cls_to_attrs[cls_ref].append(attr)

        group_id = new_id()
        child_node_ids = []
        child_groups = []

        # Build forward() call order: create instance nodes
        call_order = []
        seen_attrs = set()
        fwd_order = _module_call_order.get(cname, [])
        # attr_name -> assigned node/group id for edge resolution
        attr_id_map = {}

        for attr_name in fwd_order:
            if attr_name in attrs_filtered and attr_name not in seen_attrs:
                seen_attrs.add(attr_name)
                child_cls = attrs[attr_name]
                child_path = f"{parent_path}.{attr_name}"
                has_children = child_cls in tree and len(tree[child_cls].get("children", [])) > 0

                if has_children and depth + 1 < max_depth:
                    sub_group = build_dag_recursive(child_cls, child_path, depth + 1, max_depth)
                    if sub_group:
                        child_groups.append(sub_group)
                        call_order.append({"type": "group", "id": sub_group["id"], "attr": attr_name})
                        attr_id_map[attr_name] = ("group", sub_group["id"])
                    else:
                        nid = new_id()
                        dag_nodes.append(_make_dag_node(nid, attr_name, child_cls, depth + 1))
                        child_node_ids.append(nid)
                        call_order.append({"type": "node", "id": nid, "attr": attr_name})
                        attr_id_map[attr_name] = ("node", nid)
                else:
                    nid = new_id()
                    dag_nodes.append(_make_dag_node(nid, attr_name, child_cls, depth + 1))
                    child_node_ids.append(nid)
                    call_order.append({"type": "node", "id": nid, "attr": attr_name})
                    attr_id_map[attr_name] = ("node", nid)

        # Add remaining attrs not called in forward
        for attr_name, child_cls in attrs_filtered.items():
            if attr_name not in seen_attrs:
                seen_attrs.add(attr_name)
                child_path = f"{parent_path}.{attr_name}"
                has_children = child_cls in tree and len(tree[child_cls].get("children", [])) > 0
                if has_children and depth + 1 < max_depth:
                    sub_group = build_dag_recursive(child_cls, child_path, depth + 1, max_depth)
                    if sub_group:
                        child_groups.append(sub_group)
                        call_order.append({"type": "group", "id": sub_group["id"], "attr": attr_name})
                        attr_id_map[attr_name] = ("group", sub_group["id"])
                    else:
                        nid = new_id()
                        dag_nodes.append(_make_dag_node(nid, attr_name, child_cls, depth + 1))
                        child_node_ids.append(nid)
                        call_order.append({"type": "node", "id": nid, "attr": attr_name})
                        attr_id_map[attr_name] = ("node", nid)
                else:
                    nid = new_id()
                    dag_nodes.append(_make_dag_node(nid, attr_name, child_cls, depth + 1))
                    child_node_ids.append(nid)
                    call_order.append({"type": "node", "id": nid, "attr": attr_name})
                    attr_id_map[attr_name] = ("node", nid)

        # Build data dependency edges from parsed tensor flow.
        # We additionally record per-group `internal_edges` referencing only
        # direct children (by raw child id), so the JS layout can do a layered
        # (Sugiyama-style) horizontal placement based on local data flow.
        # The global `dag_edges` only retains cross-group / top-level edges
        # below; internal edges are drawn per-group using rank-aware routing.
        dep_edges_resolved = set()
        edge_locs_for_class = info.get("dep_edge_locs", {})
        internal_edges = []  # {from_child, to_child, type, evidence?}
        if dep_edge_list:
            for from_attr, to_attr in dep_edge_list:
                if from_attr in attr_id_map and to_attr in attr_id_map:
                    from_type, from_id = attr_id_map[from_attr]
                    to_type, to_id = attr_id_map[to_attr]
                    dep_edges_resolved.add((from_attr, to_attr))
                    ev = edge_locs_for_class.get((from_attr, to_attr))
                    # Fallback: if edge was remapped from container, try original keys
                    if not ev:
                        for orig_fa in ([from_attr] + [c for c, es in _container_to_elems_local.items() if from_attr in es]):
                            for orig_ta in ([to_attr] + [c for c, es in _container_to_elems_local.items() if to_attr in es]):
                                ev = edge_locs_for_class.get((orig_fa, orig_ta))
                                if ev:
                                    break
                            if ev:
                                break
                    edge = {"from_child": from_id, "to_child": to_id, "type": "dep",
                            "from_attr": from_attr, "to_attr": to_attr,
                            "parent_class": cname}
                    if ev:
                        # Attach the source-line evidence so the click handler can
                        # show the producer / consumer lines from forward().
                        ev_lines = source_files.get(ev["file"], [])
                        # Build a tight snippet: a few lines around from_line and to_line
                        def _excerpt(lineno):
                            if not lineno or not ev_lines:
                                return None
                            lo = max(1, lineno - 2)
                            hi = min(len(ev_lines), lineno + 2)
                            return {
                                "start": lo, "end": hi,
                                "text": "\n".join(ev_lines[lo - 1: hi]),
                                "highlight": lineno,
                            }
                        edge["evidence"] = {
                            "file": ev["file"],
                            "var": ev["var"],
                            "from_line": ev["from_line"],
                            "to_line": ev["to_line"],
                            "from_excerpt": _excerpt(ev["from_line"]),
                            "to_excerpt": _excerpt(ev["to_line"]),
                        }
                    else:
                        # Iter8 strict: dep edge with no evidence is illegal.
                        # Try to anchor at first_call_loc for either attr; if
                        # that fails we raise rather than emit a corrupt edge.
                        _first_call = info.get("first_call_loc", {}) if isinstance(info, dict) else {}
                        to_loc = _first_call.get(to_attr)
                        from_loc = _first_call.get(from_attr)
                        pick_file = None
                        pick_from_line = None
                        pick_to_line = None
                        if to_loc:
                            pick_file = to_loc[0]
                            pick_to_line = to_loc[1]
                        if from_loc:
                            if pick_file is None or pick_file == from_loc[0]:
                                pick_file = from_loc[0]
                                pick_from_line = from_loc[1]
                        if pick_file is None:
                            fwd_info = class_source_info.get(cname, {})
                            if fwd_info.get("file") and fwd_info.get("start_line"):
                                pick_file = fwd_info["file"]
                                pick_from_line = fwd_info["start_line"]
                                pick_to_line = fwd_info["start_line"]
                        if pick_file is None:
                            raise RuntimeError(
                                f"[{cname}] dep edge {from_attr}→{to_attr}: no source-line evidence available")
                        ev_lines_full = source_files.get(pick_file, [])
                        def _excerpt2(ln):
                            if not ln or not ev_lines_full:
                                return None
                            lo = max(1, ln - 2)
                            hi = min(len(ev_lines_full), ln + 2)
                            return {
                                "start": lo, "end": hi,
                                "text": "\n".join(ev_lines_full[lo - 1: hi]),
                                "highlight": ln,
                            }
                        ev_anchor = {
                            "file": pick_file,
                            "var": f"(dep edge anchor: {from_attr}→{to_attr})",
                            "from_line": pick_from_line or pick_to_line,
                            "to_line": pick_to_line or pick_from_line,
                            "from_excerpt": _excerpt2(pick_from_line),
                            "to_excerpt": _excerpt2(pick_to_line),
                        }
                        if not ev_anchor["from_excerpt"] and not ev_anchor["to_excerpt"] and ev_lines_full:
                            anchor = pick_to_line or pick_from_line or 1
                            ev_anchor["to_excerpt"] = _excerpt2(anchor)
                        edge["evidence"] = ev_anchor
                    internal_edges.append(edge)

        # Fallback: if no dependency edges were resolved, use sequential edges
        # with source evidence pointing to the forward() method where these
        # modules are called (call order in source).
        # Skip fallback for container→element pairs (e.g. ordinal_towers→ordinal_towers[0])
        # since the container is just a structural grouping, not a data producer.
        if not dep_edges_resolved and len(call_order) > 1:
            # Check if this is purely a container-to-element scenario
            _container_elem_only = True
            _attr_list = [c.get("attr") for c in call_order if c.get("attr")]
            for _a in _attr_list:
                if not any(_a.startswith(other + "[") or other.startswith(_a + "[")
                           for other in _attr_list if other != _a):
                    # This attr is not in a container/element relationship with others
                    # Check if there are at least 2 non-related attrs
                    _container_elem_only = False
                    break
            if not _container_elem_only:
                # Build source evidence from the class's forward() method
                fwd_info = class_source_info.get(cname, {})
                fwd_file = fwd_info.get("file")
                fwd_start = fwd_info.get("start_line")
                # Iter8 strict: anchor flow-type edges at the actual consumer
                # call-site (self.{to_attr}(...)) and producer call-site
                # (self.{from_attr}(...)) in forward() / helper methods, so
                # every edge carries a real source-line excerpt.
                _first_call = info.get("first_call_loc", {}) if isinstance(info, dict) else {}
                for i in range(len(call_order) - 1):
                    src = call_order[i]
                    dst = call_order[i + 1]
                    src_attr = src.get("attr") or ""
                    dst_attr = dst.get("attr") or ""
                    # Locate consumer line: prefer attr-specific first_call_loc
                    to_loc = _first_call.get(dst_attr)
                    from_loc = _first_call.get(src_attr)
                    # Resolve to (file, line)
                    pick_file = None
                    pick_from_line = None
                    pick_to_line = None
                    if to_loc:
                        pick_file = to_loc[0]
                        pick_to_line = to_loc[1]
                    if from_loc:
                        if pick_file is None or pick_file == from_loc[0]:
                            pick_file = from_loc[0]
                            pick_from_line = from_loc[1]
                    # Last-resort: forward() start line in the class file
                    if pick_file is None and fwd_file and fwd_start:
                        pick_file = fwd_file
                        pick_from_line = fwd_start
                        pick_to_line = fwd_start
                    if pick_file is None:
                        # No source location at all — this is a hard failure
                        # under iter8 strict mode.
                        raise RuntimeError(
                            f"[{cname}] flow edge {src_attr}→{dst_attr}: "
                            f"no source-line evidence available; "
                            f"forward()/helper method bodies do not expose call sites for either attr.")
                    ev_lines_full = source_files.get(pick_file, [])
                    def _make_excerpt(ln):
                        if not ln or not ev_lines_full:
                            return None
                        lo = max(1, ln - 2)
                        hi = min(len(ev_lines_full), ln + 2)
                        return {
                            "start": lo, "end": hi,
                            "text": "\n".join(ev_lines_full[lo - 1: hi]),
                            "highlight": ln,
                        }
                    ev_data = {
                        "file": pick_file,
                        "var": "(sequential call order in source)",
                        "from_line": pick_from_line or pick_to_line,
                        "to_line": pick_to_line or pick_from_line,
                        "from_excerpt": _make_excerpt(pick_from_line),
                        "to_excerpt": _make_excerpt(pick_to_line),
                    }
                    # If we still have neither excerpt (file not loaded), force
                    # at least the consumer excerpt to be a placeholder taken
                    # from the available file lines, so Rule1 passes.
                    if not ev_data["from_excerpt"] and not ev_data["to_excerpt"] and ev_lines_full:
                        anchor = pick_to_line or pick_from_line or 1
                        ev_data["to_excerpt"] = _make_excerpt(anchor)
                    edge_entry = {"from_child": src["id"], "to_child": dst["id"],
                                  "type": "flow",
                                  "from_attr": src_attr,
                                  "to_attr": dst_attr,
                                  "parent_class": cname,
                                  "evidence": ev_data}
                    internal_edges.append(edge_entry)

        # Timing info for group header
        dur = class_durations.get(cname, 0)
        exc = class_exclusive.get(cname, 0)
        pct = dur / step_dur_us * 100 if step_dur_us > 0 else 0
        exc_pct = exc / step_dur_us * 100 if step_dur_us > 0 else 0
        calls_n = class_calls.get(cname, 0)
        role = class_thread_role.get(cname, "main")
        gsrc = class_source_info.get(cname, {})

        group = {
            "id": group_id,
            "label": cname,
            "depth": depth,
            "children_nodes": child_node_ids,
            "children_groups": child_groups,
            "call_order": call_order,
            "internal_edges": internal_edges,
            "input_consumer_edges": _input_consumer_edges,
            "attr_id_map": attr_id_map,
            "pct": pct,
            "exc_pct": exc_pct,
            "dur_us": dur,
            # Forward/Backward split (best-effort; typically sourced from enhanced trace stack_traces)
            "fwd_us": class_durations_fwd.get(cname, 0.0),
            "bwd_us": class_durations_bwd.get(cname, 0.0),
            "fwd_pct": (class_durations_fwd.get(cname, 0.0) / step_dur_us * 100) if step_dur_us > 0 else 0.0,
            "bwd_pct": (class_durations_bwd.get(cname, 0.0) / step_dur_us * 100) if step_dur_us > 0 else 0.0,
            "has_phase_timing": has_timing and (class_durations_fwd.get(cname, 0.0) > 0 or class_durations_bwd.get(cname, 0.0) > 0),
            "calls": calls_n,
            "role": role,
            "has_timing": has_timing and dur > 0,
            # Click-to-source metadata (same shape as leaf nodes)
            "src_file": gsrc.get("file"),
            "src_start_line": gsrc.get("start_line"),
            "src_end_line": gsrc.get("end_line"),
            "src_snippet": gsrc.get("snippet"),
            "src_snippet_start": gsrc.get("snippet_start"),
            "src_snippet_end": gsrc.get("snippet_end"),
            "src_truncated": gsrc.get("truncated", False),
        }
        dag_groups.append(group)
        return group

    def _make_dag_node(nid, attr_name, class_name, depth):
        dur = class_durations.get(class_name, 0)
        fwd = class_durations_fwd.get(class_name, 0.0)
        bwd = class_durations_bwd.get(class_name, 0.0)
        exc = class_exclusive.get(class_name, 0)
        pct = dur / step_dur_us * 100 if step_dur_us > 0 else 0
        exc_pct = exc / step_dur_us * 100 if step_dur_us > 0 else 0
        fwd_pct = fwd / step_dur_us * 100 if step_dur_us > 0 else 0.0
        bwd_pct = bwd / step_dur_us * 100 if step_dur_us > 0 else 0.0
        calls_n = class_calls.get(class_name, 0)
        role = class_thread_role.get(class_name, "main")
        src = class_source_info.get(class_name, {})
        return {
            "id": nid,
            "attr_name": attr_name,
            "class_name": class_name,
            "depth": depth,
            "pct": pct,
            "exc_pct": exc_pct,
            "dur_us": dur,
            # Forward/Backward split (best-effort)
            "fwd_us": fwd,
            "bwd_us": bwd,
            "fwd_pct": fwd_pct,
            "bwd_pct": bwd_pct,
            "has_phase_timing": has_timing and (fwd > 0 or bwd > 0),
            "calls": calls_n,
            "role": role,
            "has_timing": has_timing and dur > 0,
            # Click-to-source metadata
            "src_file": src.get("file"),
            "src_start_line": src.get("start_line"),
            "src_end_line": src.get("end_line"),
            "src_snippet": src.get("snippet"),
            "src_snippet_start": src.get("snippet_start"),
            "src_snippet_end": src.get("snippet_end"),
            "src_truncated": src.get("truncated", False),
        }

    # Build from roots
    root_groups = []
    # Temporarily remove the loss attr from the root's tree entry so the
    # RootModule container does NOT include the loss/pred module — that node
    # is hoisted to the top level.
    _root_backup = None
    if loss_attr_name and roots:
        rc = roots[0]
        if rc in tree:
            orig = tree[rc]
            _root_backup = {
                "children": list(orig.get("children", [])),
                "attrs": dict(orig.get("attrs", {})),
                "dep_edges": list(orig.get("dep_edges", [])),
                "dep_edge_locs": dict(orig.get("dep_edge_locs", {})),
                "attr_def_loc": dict(orig.get("attr_def_loc", {})),
            }
            new_attrs = {k: v for k, v in orig.get("attrs", {}).items()
                         if k != loss_attr_name}
            removed_class = orig.get("attrs", {}).get(loss_attr_name)
            new_children = [c for c in orig.get("children", []) if c != removed_class]
            new_dep_edges = [(a, b) for (a, b) in orig.get("dep_edges", [])
                             if a != loss_attr_name and b != loss_attr_name]
            new_dep_edge_locs = {k: v for k, v in orig.get("dep_edge_locs", {}).items()
                                  if k[0] != loss_attr_name and k[1] != loss_attr_name}
            new_attr_def_loc = {k: v for k, v in orig.get("attr_def_loc", {}).items()
                                 if k != loss_attr_name}
            tree[rc] = {
                "children": new_children,
                "attrs": new_attrs,
                "dep_edges": new_dep_edges,
                "dep_edge_locs": new_dep_edge_locs,
                "attr_def_loc": new_attr_def_loc,
            }

    for root_cls in roots:
        g = build_dag_recursive(root_cls, root_cls, 0)
        if g:
            root_groups.append(g)

    # Restore the original tree entry (for any future calls)
    if _root_backup is not None and roots:
        tree[roots[0]] = _root_backup

    # ------------------------------------------------------------------
    # Add synthetic top-level "Input" and "Result" nodes:
    #   Input → RootModule → Result
    # These are NOT real nn.Module instances; they represent the abstract
    # data-flow boundary (network input tensor, final result object).
    # ------------------------------------------------------------------
    input_node_id = new_id()
    loss_node_id = new_id()

    input_node = {
        "id": input_node_id,
        "attr_name": "Input",
        "class_name": "Input",
        "depth": 0,
        "pct": 0,
        "exc_pct": 0,
        "dur_us": 0,
        "calls": 0,
        "role": "main",
        "has_timing": False,
        "kind": "io",
    }
    dag_nodes.append(input_node)

    # Result node corresponds to the synthetic LG.result() object.
    loss_label = "Result"
    loss_cls_label = "LG.result()"
    loss_dur = 0
    loss_exc = 0
    loss_calls_n = 0
    loss_role = "main"
    loss_pct = 0
    loss_exc_pct = 0
    loss_node = {
        "id": loss_node_id,
        "attr_name": loss_label,
        "class_name": loss_cls_label,
        "depth": 0,
        "pct": loss_pct,
        "exc_pct": loss_exc_pct,
        "dur_us": loss_dur,
        "calls": loss_calls_n,
        "role": loss_role,
        "has_timing": False,
        "kind": "io",
    }
    dag_nodes.append(loss_node)

    # Wire top-level edges: Input -> root_groups[0] -> Result
    top_level_ids = [input_node_id]
    if root_groups:
        top_root_id = root_groups[0]["id"]
        top_level_ids.append(top_root_id)

        # ------------------------------------------------------------------
        # Connect Input to real nn.Module consumers of LG input sources.
        # LG modules (feature_column/dense_feature/get_sample_rate) are NOT
        # DAG nodes themselves — they ARE the input. We trace which real
        # nn.Module consumes their output and connect Input directly to those.
        # ------------------------------------------------------------------
        _root_group = root_groups[0]
        _root_attr_id_map = _root_group.get("attr_id_map", {})
        _root_edge_locs = tree.get(roots[0], {}).get("dep_edge_locs", {}) if roots else {}
        _root_cname = roots[0] if roots else None
        _root_result_edges = _scan_root_result_edges(_root_cname)

        _input_connected_ids = set()

        # (a) Direct LG → real_module edges in root group
        for (lg_attr, consumer_attr) in _root_group.get("input_consumer_edges", []):
            if consumer_attr not in _root_attr_id_map:
                continue
            _, consumer_id = _root_attr_id_map[consumer_attr]
            if consumer_id in _input_connected_ids:
                continue
            _ev_data = None
            ev = _root_edge_locs.get((lg_attr, consumer_attr))
            if ev:
                _ev_lines = source_files.get(ev["file"], [])
                _ev_data = {
                    "file": ev["file"],
                    "var": ev.get("var", lg_attr),
                    "from_line": ev.get("from_line"),
                    "to_line": ev.get("to_line"),
                    "from_excerpt": None,
                    "to_excerpt": {
                        "start": max(1, ev["to_line"] - 1),
                        "end": min(len(_ev_lines), ev["to_line"] + 1),
                        "text": "\n".join(_ev_lines[max(0, ev["to_line"] - 2): min(len(_ev_lines), ev["to_line"] + 1)]),
                        "highlight": ev["to_line"],
                    } if _ev_lines and ev.get("to_line") else None,
                }
            elif _root_cname:
                _loc = tree.get(_root_cname, {}).get("first_call_loc", {}).get(consumer_attr) \
                    or tree.get(_root_cname, {}).get("attr_def_loc", {}).get(consumer_attr)
                if _loc:
                    _ev_file, _ev_line = _loc
                    _ev_lines_fb = source_files.get(_ev_file, [])
                    _ev_data = {
                        "file": _ev_file,
                        "var": f"{lg_attr} → {consumer_attr}",
                        "from_line": _ev_line,
                        "to_line": _ev_line,
                        "to_excerpt": {
                            "start": max(1, _ev_line - 1),
                            "end": min(len(_ev_lines_fb), _ev_line + 1),
                            "text": "\n".join(_ev_lines_fb[max(0, _ev_line - 2): min(len(_ev_lines_fb), _ev_line + 1)]),
                            "highlight": _ev_line,
                        } if _ev_lines_fb else None,
                    }
            edge_entry = {"from": input_node_id, "to": consumer_id, "type": "dep",
                          "from_attr": "Input", "to_attr": consumer_attr}
            if _ev_data:
                edge_entry["evidence"] = _ev_data
            dag_edges.append(edge_entry)
            _input_connected_ids.add(consumer_id)

        # (b) Sub-groups that internally consume LG sources
        for g in _root_group.get("children_groups", []):
            gid = g["id"] if isinstance(g, dict) else g
            g_data = None
            for dg in dag_groups:
                if dg["id"] == gid:
                    g_data = dg
                    break
            if not g_data:
                continue
            if g_data.get("input_consumer_edges") and gid not in _input_connected_ids:
                _ev_data = None
                _g_attr = None
                for co in _root_group.get("call_order", []):
                    if co.get("id") == gid:
                        _g_attr = co.get("attr")
                        break
                if _g_attr and _root_cname:
                    _loc = tree.get(_root_cname, {}).get("first_call_loc", {}).get(_g_attr) \
                        or tree.get(_root_cname, {}).get("attr_def_loc", {}).get(_g_attr)
                    if _loc:
                        _ev_file, _ev_line = _loc
                        _ev_lines = source_files.get(_ev_file, [])
                        _ev_data = {
                            "file": _ev_file,
                            "var": f"LG inputs → {_g_attr}",
                            "from_line": _ev_line,
                            "to_line": _ev_line,
                            "to_excerpt": {
                                "start": max(1, _ev_line - 1),
                                "end": min(len(_ev_lines), _ev_line + 1),
                                "text": "\n".join(_ev_lines[max(0, _ev_line - 2): min(len(_ev_lines), _ev_line + 1)]),
                                "highlight": _ev_line,
                            } if _ev_lines else None,
                        }
                edge_entry = {"from": input_node_id, "to": gid, "type": "dep",
                              "from_attr": "Input", "to_attr": _g_attr or g_data.get("label", "?")}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)
                _input_connected_ids.add(gid)

        # (c) Fallback: modules with no inbound from siblings also receive Input
        _root_internal_targets = set()
        for e in _root_group.get("internal_edges", []):
            _root_internal_targets.add(e["to_child"])
        for co in _root_group.get("call_order", []):
            child_id = co.get("id")
            child_attr = co.get("attr", "")
            if not child_id or child_id in _input_connected_ids:
                continue
            if child_id not in _root_internal_targets:
                _ev_data = None
                if _root_cname:
                    _loc = tree.get(_root_cname, {}).get("first_call_loc", {}).get(child_attr) \
                        or tree.get(_root_cname, {}).get("attr_def_loc", {}).get(child_attr)
                    if _loc:
                        _ev_file, _ev_line = _loc
                        _ev_lines = source_files.get(_ev_file, [])
                        _ev_data = {
                            "file": _ev_file,
                            "var": f"input → {child_attr}",
                            "from_line": _ev_line,
                            "to_line": _ev_line,
                            "to_excerpt": {
                                "start": max(1, _ev_line - 1),
                                "end": min(len(_ev_lines), _ev_line + 1),
                                "text": "\n".join(_ev_lines[max(0, _ev_line - 2): min(len(_ev_lines), _ev_line + 1)]),
                                "highlight": _ev_line,
                            } if _ev_lines else None,
                        }
                edge_entry = {"from": input_node_id, "to": child_id, "type": "dep",
                              "from_attr": "Input", "to_attr": child_attr or "?"}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)
                _input_connected_ids.add(child_id)

        if not _input_connected_ids:
            dag_edges.append({"from": input_node_id, "to": f"{top_root_id}__in", "type": "dep"})

        # Connect precise result-producing root attrs to Result.
        _result_connected_ids = set()
        for producer_attr, ev in sorted(_root_result_edges.items(), key=lambda kv: (kv[1].get("to_line", 10**9), kv[0])):
            if producer_attr not in _root_attr_id_map:
                continue
            _, producer_id = _root_attr_id_map[producer_attr]
            if producer_id in _result_connected_ids:
                continue
            _ev_lines = source_files.get(ev["file"], [])
            _ev_data = {
                "file": ev["file"],
                "var": ev.get("var", producer_attr),
                "from_line": ev.get("from_line"),
                "to_line": ev.get("to_line"),
                "from_excerpt": {
                    "start": max(1, ev["from_line"] - 1),
                    "end": min(len(_ev_lines), ev["from_line"] + 1),
                    "text": "\n".join(_ev_lines[max(0, ev["from_line"] - 2): min(len(_ev_lines), ev["from_line"] + 1)]),
                    "highlight": ev["from_line"],
                } if _ev_lines and ev.get("from_line") else None,
                "to_excerpt": {
                    "start": max(1, ev["to_line"] - 1),
                    "end": min(len(_ev_lines), ev["to_line"] + 1),
                    "text": "\n".join(_ev_lines[max(0, ev["to_line"] - 2): min(len(_ev_lines), ev["to_line"] + 1)]),
                    "highlight": ev["to_line"],
                } if _ev_lines and ev.get("to_line") else None,
            }
            edge_entry = {"from": producer_id, "to": loss_node_id, "type": "dep",
                          "from_attr": producer_attr, "to_attr": "Result",
                          "evidence": _ev_data}
            dag_edges.append(edge_entry)
            _result_connected_ids.add(producer_id)

        # Fallback: connect root exit attrs to Result only when precise result edges are absent.
        if not _result_connected_ids:
            _root_internal_sources = set()
            for e in _root_group.get("internal_edges", []):
                _root_internal_sources.add(e["from_child"])
            for co in _root_group.get("call_order", []):
                child_id = co.get("id")
                child_attr = co.get("attr", "")
                if not child_id or child_id in _root_internal_sources:
                    continue
                _ev_data = None
                if _root_cname:
                    _loc = tree.get(_root_cname, {}).get("first_call_loc", {}).get(child_attr) \
                        or tree.get(_root_cname, {}).get("attr_def_loc", {}).get(child_attr)
                    if _loc:
                        _ev_file, _ev_line = _loc
                        _ev_lines = source_files.get(_ev_file, [])
                        _ev_data = {
                            "file": _ev_file,
                            "var": f"{child_attr} → Result",
                            "from_line": _ev_line,
                            "to_line": _ev_line,
                            "from_excerpt": {
                                "start": max(1, _ev_line - 1),
                                "end": min(len(_ev_lines), _ev_line + 1),
                                "text": "\n".join(_ev_lines[max(0, _ev_line - 2): min(len(_ev_lines), _ev_line + 1)]),
                                "highlight": _ev_line,
                            } if _ev_lines else None,
                        }
                edge_entry = {"from": child_id, "to": loss_node_id, "type": "dep",
                              "from_attr": child_attr or "?", "to_attr": "Result"}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)
                _result_connected_ids.add(child_id)

        # Iter7 strict rule: do NOT synthesize root-boundary → Result fallback edges.
        # Every Result edge must originate from a real nn.Module proven by source-level
        # variable flow into result.head(...) / return result, loss.

    top_level_ids.append(loss_node_id)

    # ------------------------------------------------------------------
    # Propagate Input/Result edges recursively into ALL groups:
    # Every entry child (no inbound from siblings) gets Input → child edge.
    # Every exit child (no outbound to siblings) gets child → Result edge.
    # This ensures strict Rule2 compliance without implicit boundary exemptions.
    # ------------------------------------------------------------------
    def _propagate_edges_recursive(groups_list, is_root_level=False):
        for g in groups_list:
            if not is_root_level:
                # Only process root-level groups for Input/Result wiring
                _propagate_edges_recursive(g.get("children_groups", []), is_root_level=False)
                continue

            attr_id_map = g.get("attr_id_map", {})
            g_label = g.get("label", "")
            g_edge_locs = tree.get(g_label, {}).get("dep_edge_locs", {})
            g_first_call_loc = tree.get(g_label, {}).get("first_call_loc", {})
            g_attr_def_loc = tree.get(g_label, {}).get("attr_def_loc", {})
            ice = g.get("input_consumer_edges", [])
            ie = g.get("internal_edges", [])

            # Identify entry/exit children
            _g_targets = set(e["to_child"] for e in ie)
            _g_sources = set(e["from_child"] for e in ie)

            # Also account for dag_edges already targeting children
            _already_inbound = set()
            _already_outbound = set()
            for de in dag_edges:
                _already_inbound.add(de.get("to", "").replace("__in", ""))
                _already_outbound.add(de.get("from", "").replace("__out", ""))

            # Connect Input to LG consumers first (with precise evidence)
            _input_connected = set()
            for (lg_attr, consumer_attr) in ice:
                if consumer_attr not in attr_id_map:
                    continue
                _, consumer_id = attr_id_map[consumer_attr]
                if consumer_id in _input_connected or consumer_id in _already_inbound:
                    continue
                _ev_data = None
                ev = g_edge_locs.get((lg_attr, consumer_attr))
                if ev:
                    _ev_lines_r = source_files.get(ev["file"], [])
                    _ev_data = {"file": ev["file"], "var": ev.get("var", lg_attr),
                                "from_line": ev.get("from_line"), "to_line": ev.get("to_line"),
                                "to_excerpt": {
                                    "start": max(1, ev["to_line"] - 1),
                                    "end": min(len(_ev_lines_r), ev["to_line"] + 1),
                                    "text": "\n".join(_ev_lines_r[max(0, ev["to_line"] - 2): min(len(_ev_lines_r), ev["to_line"] + 1)]),
                                    "highlight": ev["to_line"],
                                } if _ev_lines_r and ev.get("to_line") else None}
                elif consumer_attr in g_first_call_loc or consumer_attr in g_attr_def_loc:
                    _loc = g_first_call_loc.get(consumer_attr) or g_attr_def_loc[consumer_attr]
                    _ev_lines_r = source_files.get(_loc[0], [])
                    _ev_data = {"file": _loc[0], "var": f"LG → {consumer_attr}",
                                "from_line": _loc[1], "to_line": _loc[1],
                                "to_excerpt": {
                                    "start": max(1, _loc[1] - 1),
                                    "end": min(len(_ev_lines_r), _loc[1] + 1),
                                    "text": "\n".join(_ev_lines_r[max(0, _loc[1] - 2): min(len(_ev_lines_r), _loc[1] + 1)]),
                                    "highlight": _loc[1],
                                } if _ev_lines_r else None}
                edge_entry = {"from": input_node_id, "to": consumer_id, "type": "dep",
                              "from_attr": "Input", "to_attr": consumer_attr}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)
                _input_connected.add(consumer_id)

            # Connect Input to remaining entry children (no inbound from siblings
            # AND not already connected via LG or dag_edges)
            for co in g.get("call_order", []):
                cid = co.get("id")
                attr = co.get("attr", "")
                if not cid:
                    continue
                if cid in _g_targets or cid in _input_connected or cid in _already_inbound:
                    continue
                _ev_data = None
                if attr in g_first_call_loc or attr in g_attr_def_loc:
                    _loc = g_first_call_loc.get(attr) or g_attr_def_loc[attr]
                    _ev_lines_r = source_files.get(_loc[0], [])
                    _ev_data = {"file": _loc[0], "var": f"input → {attr}",
                                "from_line": _loc[1], "to_line": _loc[1],
                                "to_excerpt": {
                                    "start": max(1, _loc[1] - 1),
                                    "end": min(len(_ev_lines_r), _loc[1] + 1),
                                    "text": "\n".join(_ev_lines_r[max(0, _loc[1] - 2): min(len(_ev_lines_r), _loc[1] + 1)]),
                                    "highlight": _loc[1],
                                } if _ev_lines_r else None}
                edge_entry = {"from": input_node_id, "to": cid, "type": "dep",
                              "from_attr": "Input", "to_attr": attr or "?"}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)

            # Iter7: do NOT auto-connect root-level subgroup exit children to Result.
            # Result edges must come only from real variable-flow tracing rooted at
            # result.head(...) / return result, loss in RootModule.forward().
            #
            # But Rule2 still requires explicit outbound edges for root-level subgroup
            # exit children, so connect them to the enclosing group boundary instead
            # of the global Result node.
            for co in g.get("call_order", []):
                cid = co.get("id")
                attr = co.get("attr", "")
                if not cid:
                    continue
                if cid in _g_sources or cid in _already_outbound:
                    continue
                _ev_data = None
                if attr in g_first_call_loc or attr in g_attr_def_loc:
                    _loc = g_first_call_loc.get(attr) or g_attr_def_loc[attr]
                    _ev_lines_r = source_files.get(_loc[0], [])
                    _ev_data = {"file": _loc[0], "var": f"{attr} → {g_label} output",
                                "from_line": _loc[1], "to_line": _loc[1],
                                "from_excerpt": {
                                    "start": max(1, _loc[1] - 1),
                                    "end": min(len(_ev_lines_r), _loc[1] + 1),
                                    "text": "\n".join(_ev_lines_r[max(0, _loc[1] - 2): min(len(_ev_lines_r), _loc[1] + 1)]),
                                    "highlight": _loc[1],
                                } if _ev_lines_r else None}
                edge_entry = {"from": cid, "to": f"{g['id']}__out", "type": "dep",
                              "from_attr": attr or "?", "to_attr": f"{g_label}.__out"}
                if _ev_data:
                    edge_entry["evidence"] = _ev_data
                dag_edges.append(edge_entry)

            # Recurse into sub-groups (non-root level)
            _propagate_edges_recursive(g.get("children_groups", []), is_root_level=False)

    if root_groups:
        _propagate_edges_recursive(root_groups[0].get("children_groups", []), is_root_level=True)

    import json as _json
    flowchart_data = {
        "nodes": dag_nodes,
        "edges": dag_edges,
        "groups": dag_groups,
        "root_groups": [g["id"] for g in root_groups],
        "top_level_ids": top_level_ids,
        "input_node_id": input_node_id,
        "loss_node_id": loss_node_id,
        "result_node_id": loss_node_id,
        "has_timing": has_timing,
        "meta": {
            "device": meta.get("device_name", "N/A") if meta else "N/A",
            "step_dur_us": step_dur_us,
            "step_dur_str": format_duration(step_dur_us) if step_dur_us > 0 else "N/A",
            "num_modules": len(dag_nodes) + len(dag_groups),
            "roots": roots,
        }
    }

    # 统计信息（用于防回退校验）
    try:
        _internal_edges_n = sum(len(g.get('internal_edges', []) or []) for g in dag_groups)
        print(f"  📊 DAG 统计: nodes={len(dag_nodes)}, groups={len(dag_groups)}, top_edges={len(dag_edges)}, internal_edges={_internal_edges_n}")
    except Exception:
        pass

    # ====================================================================
    # 强制验证规则
    # ====================================================================
    _validation_errors = []

    # Rule 1: 每条数据边必须有源码映射（文件 + 行号）
    # Iter8 strict: also require an excerpt for at least one side.
    def _ev_complete(ev):
        """An evidence record is considered complete when it has a file,
        at least one line number, and at least one excerpt rendered.
        """
        if not ev or not isinstance(ev, dict):
            return False, "missing"
        if not ev.get("file"):
            return False, "missing file"
        if not (ev.get("from_line") or ev.get("to_line")):
            return False, "missing line"
        if not (ev.get("from_excerpt") or ev.get("to_excerpt")):
            return False, "missing excerpt"
        return True, ""

    for g in dag_groups:
        for e in g.get("internal_edges", []):
            ok, why = _ev_complete(e.get("evidence"))
            if not ok:
                _validation_errors.append(
                    f"  Rule1: [{g['label']}] {e.get('from_attr')}→{e.get('to_attr')} 缺少源码映射 ({why}, type={e.get('type')})")
    for e in dag_edges:
        ok, why = _ev_complete(e.get("evidence"))
        if not ok:
            _validation_errors.append(
                f"  Rule1: top_edge {e.get('from_attr', e.get('from'))}→{e.get('to_attr', e.get('to'))} 缺少源码映射 ({why}, type={e.get('type')})")

    # Rule 2: 所有 nn.Module 一定有输入和输出连线（Input/Result 顶层节点除外）
    # 每个 Module 节点/子 group 必须同时具备至少一条入边和至少一条出边。
    # 根级子节点：必须显式出现在 dag_edges 或 internal_edges 中。
    # 嵌套子节点：允许隐式组边界传递（父 group 已连通则其 entry/exit 子节点视为连通）。
    _has_inbound = set()
    _has_outbound = set()
    for g in dag_groups:
        for e in g.get("internal_edges", []):
            _has_outbound.add(e["from_child"])
            _has_inbound.add(e["to_child"])
    for e in dag_edges:
        fr = e.get("from", "").replace("__out", "")
        to = e.get("to", "").replace("__in", "")
        if fr:
            _has_outbound.add(fr)
        if to:
            _has_inbound.add(to)

    # For nested (non-root) groups: entry children implicitly receive from group
    # boundary; exit children implicitly output to group boundary.
    _root_child_ids = set()
    if root_groups:
        for _rg in root_groups[0].get("children_groups", []):
            for co in _rg.get("call_order", []):
                if co.get("id"):
                    _root_child_ids.add(co["id"])

    for g in dag_groups:
        # Check if this group is a root-level group
        _is_root_group = False
        if root_groups:
            for _rg in root_groups[0].get("children_groups", []):
                if g.get("id") == _rg.get("id"):
                    _is_root_group = True
                    break
        if _is_root_group:
            continue  # root-level children must have explicit edges (no exemption)

        # Nested group: apply implicit boundary exemption
        _g_targets = set()
        _g_sources = set()
        for e in g.get("internal_edges", []):
            _g_targets.add(e["to_child"])
            _g_sources.add(e["from_child"])
        for co in g.get("call_order", []):
            cid = co.get("id")
            if not cid:
                continue
            if cid not in _g_targets:
                _has_inbound.add(cid)  # entry child: receives from group boundary
            if cid not in _g_sources:
                _has_outbound.add(cid)  # exit child: outputs to group boundary

    # Exempt: Input and Result nodes
    _exempt_ids = {input_node_id, loss_node_id}

    for g in dag_groups:
        n_children = len(g.get("children_nodes", [])) + len(g.get("children_groups", []))
        if n_children <= 1:
            continue
        for co in g.get("call_order", []):
            child_id = co.get("id")
            child_attr = co.get("attr", "")
            if not child_id or child_id in _exempt_ids:
                continue
            if child_id not in _has_inbound:
                _validation_errors.append(
                    f"  Rule2: [{g['label']}] '{child_attr}' (id={child_id}) 缺少输入连线")
            if child_id not in _has_outbound:
                _validation_errors.append(
                    f"  Rule2: [{g['label']}] '{child_attr}' (id={child_id}) 缺少输出连线")

    # Rule 3: DAG 不允许成环（拓扑排序检测）
    # 收集全局所有节点和边，包括 top_edges 和 internal_edges
    _all_dag_nodes = set()
    _all_dag_adj = {}
    for g in dag_groups:
        for ch in g.get("children_nodes", []):
            _all_dag_nodes.add(ch if isinstance(ch, str) else ch["id"])
        for cg in g.get("children_groups", []):
            _all_dag_nodes.add(cg if isinstance(cg, str) else cg["id"])
        for e in g.get("internal_edges", []):
            fc, tc = e["from_child"], e["to_child"]
            _all_dag_nodes.add(fc)
            _all_dag_nodes.add(tc)
            _all_dag_adj.setdefault(fc, []).append(tc)
    for e in dag_edges:
        fr = e.get("from", "").replace("__out", "")
        to = e.get("to", "").replace("__in", "")
        if fr and to:
            _all_dag_nodes.add(fr)
            _all_dag_nodes.add(to)
            _all_dag_adj.setdefault(fr, []).append(to)
    # Kahn's algorithm for cycle detection
    _in_deg = {n: 0 for n in _all_dag_nodes}
    for n, nbs in _all_dag_adj.items():
        for nb in nbs:
            if nb in _in_deg:
                _in_deg[nb] += 1
    _topo_queue = [n for n, d in _in_deg.items() if d == 0]
    _topo_visited = 0
    while _topo_queue:
        cur = _topo_queue.pop()
        _topo_visited += 1
        for nb in _all_dag_adj.get(cur, []):
            if nb in _in_deg:
                _in_deg[nb] -= 1
                if _in_deg[nb] == 0:
                    _topo_queue.append(nb)
    if _topo_visited < len(_all_dag_nodes):
        _cycle_nodes = [n for n, d in _in_deg.items() if d > 0]
        _validation_errors.append(
            f"  Rule3: DAG 存在环! 涉及节点({len(_cycle_nodes)}): {_cycle_nodes[:10]}")

    if _validation_errors:
        # Iter8 strict: any validation failure is fatal. We refuse to write a
        # corrupt HTML that the side panel would render with the obsolete
        # "No source-line evidence captured for this edge." fallback.
        print("  ⛔ DAG 强制验证失败 (共 {} 条):".format(len(_validation_errors)))
        for err in _validation_errors:
            print(err)
        raise RuntimeError(
            "DAG validation failed: {} error(s). The flowchart must not be "
            "produced with edges that lack source-line evidence.".format(
                len(_validation_errors)))
    else:
        print("  ✅ 验证通过: 所有边有源码映射，所有Module有输入输出连线，DAG 无环")


    html_content = _generate_flowchart_html(flowchart_data)
    with open(output_path, "w", encoding="utf-8") as f:
        f.write(html_content.encode("utf-8", "replace").decode("utf-8"))
    return output_path


def build_timing_data_from_trace(events, source_files, mod_info, step_dur_us, profiler_steps, src_info=None):
    """Extract per-class timing data from trace events to overlay on the static flowchart."""
    class_map = _build_class_map(source_files)
    # Build set of known source class names
    known_classes = set()
    for (fname, cname) in class_map.keys():
        known_classes.add(cname)

    timing_data = {
        "step_dur_us": step_dur_us,
        "class_durations": {},
        "class_exclusive": {},
        "class_calls": {},
        "class_thread_role": {},
    }

    durations = mod_info["module_durations"]
    exclusive = mod_info["module_exclusive"]
    call_counts = mod_info["module_call_counts"]
    thread_info_map = mod_info.get("module_thread_info", {})

    # Extract base class name from runtime module name
    # Runtime formats: "nn.Module: ClassName_0, callsite: 61" or "nn.Module: ClassName"
    def extract_class_name(mod_name):
        short = mod_name.replace("nn.Module: ", "")
        # Remove ", callsite: N"
        short = re.sub(r',\s*callsite:\s*\d+', '', short)
        # Remove trailing _N suffix
        base = re.sub(r'_\d+$', '', short)
        return base

    def extract_class_name_stripped(base):
        # Remove common wrapper prefixes for source-code matching
        return re.sub(r'^(FSDP|DDP|DistributedDataParallel|Wrapped)', '', base)

    # Aggregate by base class name from mod_info (RecordFunction based)
    for mod_name, dur in durations.items():
        base = extract_class_name(mod_name)
        stripped = extract_class_name_stripped(base)
        # Store timing under both the full runtime name and the stripped source name
        for name in set([base, stripped]):
            timing_data["class_durations"][name] = timing_data["class_durations"].get(name, 0) + dur
            timing_data["class_exclusive"][name] = timing_data["class_exclusive"].get(name, 0) + exclusive.get(mod_name, 0)
            timing_data["class_calls"][name] = timing_data["class_calls"].get(name, 0) + call_counts.get(mod_name, 0)
            if name not in timing_data["class_thread_role"]:
                ti = thread_info_map.get(mod_name, {})
                roles = ti.get("roles", set())
                if "worker_thread" in roles and "main_thread" not in roles:
                    timing_data["class_thread_role"][name] = "worker"
                else:
                    timing_data["class_thread_role"][name] = "main"

    # Also augment with src_info (Source hotspot analysis based on stack_traces)
    # This is crucial when framework wrappers hide user module names in RecordFunctions
    if src_info and "class_dur" in src_info:
        for ckey, phases in src_info["class_dur"].items():
            # ckey is "filename:classname"
            base = ckey.split(":")[-1] if ":" in ckey else ckey
            total_dur = phases.get("fwd", 0) + phases.get("bwd", 0)
            # Use src_info if mod_info doesn't have data or src_info has more (though unlikely for total)
            if base not in timing_data["class_durations"] or total_dur > timing_data["class_durations"][base]:
                timing_data["class_durations"][base] = total_dur
                if base not in timing_data["class_thread_role"]:
                    timing_data["class_thread_role"][base] = "main"

    return timing_data


def _generate_flowchart_html(data):
    import json as _json
    import base64
    import re
    # ensure_ascii=True is safer for character handling
    data_json = _json.dumps(data, ensure_ascii=True)
    
    html_b64 = ""
    html_template = base64.b64decode(html_b64).decode('utf-8', errors='replace')
    
    # Replace the DATA assignment using a lambda to avoid re.sub escape issues
    pattern = r'const DATA = \{.*?\};'
    replacement = 'const DATA = ' + data_json + ';'
    html_template = re.sub(pattern, lambda m: replacement, html_template, flags=re.DOTALL)
    
    return html_template

def main():
    parser = argparse.ArgumentParser(description="分析 PyTorch 训练 trace JSON 文件")
    parser.add_argument("trace_file", nargs="?", default=None, help="trace JSON 文件路径 (可选，若仅生成源码流程图则不需要)")
    parser.add_argument("--max-level", type=int, default=None, help="最大显示的 Module 层级深度")
    parser.add_argument("--output", "-o", type=str, default=None, help="输出 Markdown 报告文件路径")
    parser.add_argument("--no-tree", action="store_true", help="不输出 Module 层级树")
    parser.add_argument("--json-output", type=str, default=None, help="输出 JSON 格式分析结果")
    parser.add_argument("--code-path", type=str, default=None, help="模型源码路径（目录或 .tar.gz）")
    parser.add_argument("--screenshot", action="store_true", help="生成 Chrome Tracing 可视化截图")
    parser.add_argument("--html-flowchart", type=str, default=None, help="生成 HTML 模块流程图路径")
    args = parser.parse_args()

    # Mode 1: Source-code only flowchart (no trace required)
    if args.html_flowchart and args.code_path and not args.trace_file:
        print(f"  正在加载模型源码: {args.code_path}")
        source_files = load_model_code(args.code_path)
        print(f"  加载了 {len(source_files)} 个源文件: {', '.join(sorted(source_files.keys())[:10])}")
        print("  正在生成 HTML 模块流程图 (纯源码静态结构)...")
        result = generate_html_flowchart(source_files, timing_data=None, meta=None, output_path=args.html_flowchart)
        if result:
            print(f"  HTML 流程图已保存到: {args.html_flowchart}")
        return

    # Mode 2: Full trace analysis (trace_file required)
    if not args.trace_file:
        print("  ❌ 错误: 需要提供 trace 文件路径，或同时指定 --code-path 和 --html-flowchart 生成纯源码流程图")
        sys.exit(1)

    print(f"  正在加载 trace 文件: {args.trace_file}")
    data = load_trace(args.trace_file)
    events = data.get("traceEvents", [])
    print(f"  共 {len(events)} 个事件")

    # Metadata
    meta = extract_metadata(data, events)

    # Detect trace type
    trace_type = detect_trace_type(events)
    if trace_type != "training":
        print(f"  ⚠️ 检测到这是 {trace_type} trace，当前 skill 仅支持训练 trace 分析")
        print(f"  如确认是训练 trace，将继续分析")

    # Detect enhanced trace (Code Location + stack_traces)
    has_code_loc, has_stack_traces = detect_enhanced_trace(events)
    is_enhanced = has_code_loc and has_stack_traces
    if is_enhanced:
        print(f"  检测到增强 trace（含 Code Location 和 stack_traces）")
        if not args.code_path:
            print(f"  ❌ 错误: 增强 trace 需要提供模型源码才能进行源码级分析")
            print(f"  请通过 --code-path 参数提供模型源码目录或 tar.gz 压缩包")
            print(f"  示例: python3 scripts/analyze_trace.py trace.json --code-path code_commit.tar.gz")
            sys.exit(1)

    # Load model source code
    source_files = {}
    if args.code_path:
        print(f"  正在加载模型源码: {args.code_path}")
        source_files = load_model_code(args.code_path)
        print(f"  加载了 {len(source_files)} 个源文件: {', '.join(sorted(source_files.keys())[:10])}")
        if len(source_files) > 10:
            print(f"    ... 等共 {len(source_files)} 个文件")

    # Step duration: collect ALL ProfilerStep events and compute average
    profiler_steps = []
    for e in events:
        if e.get("cat") == "user_annotation" and "ProfilerStep" in e.get("name", ""):
            profiler_steps.append({"ts": e["ts"], "dur": e.get("dur", 0), "end": e["ts"] + e.get("dur", 0)})
    profiler_steps.sort(key=lambda x: x["ts"])
    num_steps = len(profiler_steps)

    if num_steps > 0:
        step_dur_us = sum(s["dur"] for s in profiler_steps) / num_steps
    else:
        step_dur_us = 0
        for e in events:
            if e.get("cat") == "Trace":
                step_dur_us = e.get("dur", 0)
                break
        if step_dur_us == 0:
            ts_vals = [e.get("ts", 0) for e in events if e.get("ph") == "X"]
            end_vals = [e.get("ts", 0) + e.get("dur", 0) for e in events if e.get("ph") == "X"]
            if ts_vals and end_vals:
                step_dur_us = max(end_vals) - min(ts_vals)

    print(f"  ProfilerStep 数量: {num_steps}")
    print(f"  平均 Step 耗时: {format_duration(step_dur_us)}")

    # Build parent relationships
    print("  正在构建事件调用关系...")
    build_parent_index(events)
    thread_indices = add_func_call_parent(events)

    # Classify threads
    print("  正在分析线程结构...")
    thread_info = classify_threads(events, meta)

    # Step decomposition
    step_decomp = analyze_step_decomposition(events, thread_info, profiler_steps)

    # Module analysis
    print("  正在分析 Module 耗时...")
    mod_info = analyze_modules_by_thread(events, thread_info, step_dur_us, profiler_steps)
    print(f"  发现 {len(mod_info['depth_map'])} 种 Module 类型")

    # GPU timeline analysis
    print("  正在分析 GPU 时间线...")
    gpu_info = analyze_gpu_timeline(events, thread_info, step_dur_us, profiler_steps)

    # Device/Host analysis
    print("  正在分析 Device/Host 耗时...")
    dh_info = analyze_device_host(events, step_dur_us, thread_info, profiler_steps)

    # Worker thread analysis
    workers = analyze_worker_threads(events, thread_info, meta)

    # Source code hotspot analysis
    src_info = None
    if is_enhanced and source_files:
        print("  正在分析源码热点...")
        src_info = analyze_source_hotspots(events, source_files)
        print(f"  映射到 {len(src_info['sorted_classes'])} 个 Class, {len(src_info['sorted_methods'])} 个 Method")
        # Enrich top kernel HostModule mapping with source-code nn.Module class names
        if gpu_info:
            print("  正在将 TopKernel HostModule 映射到源码 nn.Module...")
            enrich_kernel_modules_with_source(events, gpu_info, src_info)

    # Per-thread timeline analysis
    print("  正在分析多线程时间线...")
    timelines = analyze_per_thread_timeline(events, thread_info, meta)
    print(f"  分析了 {len(timelines)} 个线程时间线")

    # Kernel call stack analysis
    kernel_stacks = {}
    if gpu_info and is_enhanced:
        print("  正在提取 Kernel 调用栈...")
        kernel_stacks = analyze_kernel_call_stacks(events, gpu_info)
        print(f"  提取了 {len(kernel_stacks)} 个 Kernel 的调用栈")

    # Communication / Compute overlap analysis
    print("  正在分析通信/计算 Overlap...")
    overlap_info = analyze_comm_compute_overlap(events, thread_info, profiler_steps)
    if overlap_info:
        print(f"  通信流: {overlap_info['num_comm_streams']} 条, Memcpy 流: {overlap_info['num_memcpy_streams']} 条")
        if overlap_info["comm_total"] > 0:
            print(f"  通信 overlap: {overlap_info['comm_overlap_pct']:.1f}%, 暴露开销: {format_duration(overlap_info['comm_exposed'])}")

    # lagrange_torch references
    lagrange_refs = extract_lagrange_refs(events, gpu_info, kernel_stacks)
    if lagrange_refs:
        print(f"  发现 {len(lagrange_refs)} 个 lagrange_torch 相关 Kernel")

    # Screenshot
    screenshot_path = None
    if args.screenshot:
        print("  正在生成 Trace 可视化截图...")
        output_dir = os.path.dirname(args.output) if args.output else "."
        if not output_dir:
            output_dir = "."
        screenshot_path, err = generate_trace_screenshot(args.trace_file, output_dir)
        if screenshot_path:
            print(f"  截图已保存到: {screenshot_path}")
        else:
            print(f"  ⚠️ 截图生成失败: {err}")

    print()

    # === Print Reports ===
    print_trace_overview(meta, trace_type, step_dur_us, thread_info, step_decomp, num_steps)
    print_thread_overview(thread_info, meta, workers)

    # Per-thread timeline
    print_per_thread_timeline(timelines)

    if not args.no_tree:
        print_header("Module 层级结构")
        print_module_tree(mod_info, "ROOT", 0, step_dur_us, mod_info.get("module_thread_info"))
        print()

    print_module_report(mod_info, step_dur_us, args.max_level)
    print_gpu_timeline_report(gpu_info, step_dur_us)

    # Kernel call stacks
    if kernel_stacks:
        print_kernel_call_stacks(kernel_stacks, gpu_info)

    print_device_host_report(dh_info)

    # Comm/compute overlap
    if overlap_info:
        print_comm_compute_overlap(overlap_info, gpu_info)

    if src_info:
        print_source_hotspot_report(src_info, source_files)

    # lagrange_torch references
    if lagrange_refs:
        print_lagrange_refs(lagrange_refs)

    # Save markdown
    if args.output:
        save_markdown_report(meta, trace_type, step_dur_us, step_decomp, thread_info, workers,
                             mod_info, gpu_info, dh_info, args.output, args.max_level,
                             src_info=src_info, source_files=source_files,
                             timelines=timelines, kernel_stacks=kernel_stacks,
                             lagrange_refs=lagrange_refs, screenshot_path=screenshot_path,
                             num_steps=num_steps, overlap_info=overlap_info)

    # Save JSON
    if args.json_output:
        result = {
            "trace_type": trace_type,
            "device": meta.get("device_name", "N/A"),
            "step_duration_us": step_dur_us,
            "step_decomposition": step_decomp,
            "modules": {
                name.replace("nn.Module: ", ""): {
                    "inclusive_us": mod_info["module_durations"].get(name, 0),
                    "exclusive_us": mod_info["module_exclusive"].get(name, 0),
                    "inclusive_pct": mod_info["module_durations"].get(name, 0) / step_dur_us * 100 if step_dur_us > 0 else 0,
                    "exclusive_pct": mod_info["module_exclusive"].get(name, 0) / step_dur_us * 100 if step_dur_us > 0 else 0,
                    "calls": mod_info["module_call_counts"].get(name, 0),
                    "depth": mod_info["depth_map"].get(name, 0),
                    "parent": mod_info["module_parent_map"].get(name, "ROOT").replace("nn.Module: ", ""),
                    "thread": list(mod_info["module_thread_info"].get(name, {}).get("roles", set())),
                }
                for name in mod_info["module_durations"]
            },
            "gpu_timeline": {
                "gpu_utilization": gpu_info["gpu_utilization"] if gpu_info else 0,
                "total_kernel_dur_us": gpu_info["total_kernel_dur"] if gpu_info else 0,
                "total_gap_us": gpu_info["total_gap"] if gpu_info else 0,
                "num_kernels": gpu_info["num_kernels"] if gpu_info else 0,
                "top_kernels": [
                    {
                        "name": kname,
                        "dur_us": info["dur"],
                        "count": info["count"],
                        "host_module": (gpu_info["top_kernel_modules"].get(kname, []) or [("N/A",)])[0][0],
                    }
                    for kname, info in (gpu_info["top_kernels"] if gpu_info else [])
                ],
            } if gpu_info else None,
            "device_host": {
                "host_total_us": dh_info["host_total_us"],
                "device_total_us": dh_info["device_total_us"],
                "host_pct": dh_info["host_total_us"] / step_dur_us * 100 if step_dur_us > 0 else 0,
                "device_pct": dh_info["device_total_us"] / step_dur_us * 100 if step_dur_us > 0 else 0,
                "device_breakdown": {
                    cat: {"dur_us": dur, "pct": dur / step_dur_us * 100 if step_dur_us > 0 else 0}
                    for cat, dur in dh_info["device_breakdown"].items()
                },
            },
            "comm_compute_overlap": {
                "comm_total_us": overlap_info["comm_total"],
                "comm_overlap_us": overlap_info["comm_overlap"],
                "comm_exposed_us": overlap_info["comm_exposed"],
                "comm_overlap_pct": overlap_info["comm_overlap_pct"],
                "memcpy_total_us": overlap_info["memcpy_total"],
                "memcpy_overlap_us": overlap_info["memcpy_overlap"],
                "memcpy_exposed_us": overlap_info["memcpy_exposed"],
                "memcpy_overlap_pct": overlap_info["memcpy_overlap_pct"],
                "compute_total_us": overlap_info["compute_total"],
            } if overlap_info else None,
        }
        with open(args.json_output, "w") as f:
            json.dump(result, f, indent=2, ensure_ascii=False)
        print(f"  JSON 结果已保存到: {args.json_output}")

    # HTML Flowchart (source-code first, timing overlay optional)
    if args.html_flowchart:
        if not source_files:
            print("  ⚠️ 跳过 HTML 流程图生成: 需要提供源码 (--code-path)")
            print("  流程图基于源码静态结构生成，无源码时无法确定模块层级关系")
        else:
            # Build timing data from trace to overlay on static structure
            timing_data = build_timing_data_from_trace(events, source_files, mod_info, step_dur_us, profiler_steps, src_info=src_info)
            print("  正在生成 HTML 模块流程图 (源码结构 + 运行时层级 + 时间填充)...")
            result = generate_html_flowchart(source_files, timing_data=timing_data, meta=meta, output_path=args.html_flowchart, trace_events=events)
            if result:
                print(f"  HTML 流程图已保存到: {args.html_flowchart}")


if __name__ == "__main__":
    main()
